const d = $input.first().json;
const out = {};
for (const k of Object.keys(d)) { if (k !== '_route') out[k] = d[k]; }
return [{ json: out }];

// Sync Finalize — receives AI classification output, updates state, returns structured result
const fs = require('fs');
const pathMod = require('path');

// ─── Filesystem helpers (same paths as PQL Engine) ───
let PQL_DIR = '/tmp/pql';
const PQL_CANDIDATES = ['/home/node/.n8n/pql', '/root/.n8n/pql', '/data/pql'];
for (const candidate of PQL_CANDIDATES) {
  try {
    const parent = candidate.substring(0, candidate.lastIndexOf('/'));
    if (!fs.existsSync(parent)) continue;
    if (fs.existsSync(candidate)) { PQL_DIR = candidate; break; }
  } catch (e) { /* skip */ }
}

function kvPath(key) {
  const STATIC = {
    'pql:library:epics_json':   'library/epics.json',
    'pql:state:state_json':     'state/state.json',
    'pql:inbox:scratchpad_md':  'inbox/scratchpad.md',
    'pql:sync:pending_context': 'state/sync_pending.json',
  };
  if (STATIC[key]) return pathMod.join(PQL_DIR, STATIC[key]);
  return pathMod.join(PQL_DIR, '_misc', key.replace(/:/g, '_') + '.json');
}
function readKV(key) {
  const p = kvPath(key); if (!fs.existsSync(p)) return null;
  const raw = fs.readFileSync(p, 'utf8');
  try { return JSON.parse(raw); } catch { return raw; }
}
function writeKV(key, data) {
  const p = kvPath(key);
  const dir = pathMod.dirname(p);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(p, typeof data === 'string' ? data : JSON.stringify(data, null, 2), 'utf8');
}

// ─── Parse AI response ───
const aiOutput = $input.first().json;
const aiText = (aiOutput.text || aiOutput.output || '').trim();

const pendingCtx = readKV('pql:sync:pending_context') || {};
const state = readKV('pql:state:state_json');
const epics = readKV('pql:library:epics_json');
const dateStr = (pendingCtx.date || new Date().toISOString().slice(0, 10));
const isoNow = (pendingCtx.iso_now || new Date().toISOString());

if (!state || !epics) {
  return [{ json: { status: 'error', cmd: 'sync', message: 'No state or epics data. Run /seed first.' } }];
}

// Extract JSON from AI response (handle markdown fences)
let parsed = null;
try {
  let jsonStr = aiText;
  // Remove markdown code fences if present
  const fenceMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenceMatch) jsonStr = fenceMatch[1].trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // Try to find JSON object in the text
  const braceStart = aiText.indexOf('{');
  const braceEnd = aiText.lastIndexOf('}');
  if (braceStart >= 0 && braceEnd > braceStart) {
    try {
      parsed = JSON.parse(aiText.slice(braceStart, braceEnd + 1));
    } catch (e2) {
      return [{ json: { status: 'error', cmd: 'sync', phase: 'ai_classified', message: 'Could not parse AI classification output. Raw: ' + aiText.slice(0, 500) } }];
    }
  } else {
    return [{ json: { status: 'error', cmd: 'sync', phase: 'ai_classified', message: 'AI returned no parseable JSON. Raw: ' + aiText.slice(0, 500) } }];
  }
}

const rawClassifications = parsed.classifications || [];
let clusters = parsed.clusters || [];

// ─── VALIDATION: Filter out hallucinated items that don't match actual input ───
// Use word-overlap scoring to catch blatant hallucinations while allowing AI rephrasing.
const actualInputs = (pendingCtx.new_lines || []).map(l => l.toLowerCase().trim());
const allInputWords = new Set();
const stopWords = new Set(['the','a','an','and','or','but','in','on','at','to','for','of','with','by','from','i','we','my','our','also','need','want','have','get','do','make','is','it','this','that']);
for (const inp of actualInputs) {
  for (const w of inp.split(/\s+/)) {
    const clean = w.replace(/[^a-z0-9]/g, '');
    if (clean.length >= 3 && !stopWords.has(clean)) allInputWords.add(clean);
  }
}

function wordOverlap(text) {
  if (!text) return 0;
  const words = text.toLowerCase().split(/\s+/).map(w => w.replace(/[^a-z0-9]/g, '')).filter(w => w.length >= 3 && !stopWords.has(w));
  if (words.length === 0) return 0;
  const matches = words.filter(w => allInputWords.has(w)).length;
  return matches / words.length;
}

const classifications = rawClassifications.filter(c => {
  const origText = (c.original_text || '').toLowerCase().trim();
  const itemText = (c.item_text || '').toLowerCase().trim();
  // Accept if original_text substring-matches any actual input
  if (actualInputs.some(inp => inp === origText || inp.includes(origText) || origText.includes(inp))) return true;
  // Accept if item_text substring-matches any actual input (for split items)
  if (actualInputs.some(inp => inp.includes(itemText) || itemText.includes(inp))) return true;
  // Accept if significant word overlap exists (handles AI rephrasing)
  if (wordOverlap(origText) >= 0.25 || wordOverlap(itemText) >= 0.25) return true;
  // Reject — no meaningful connection to actual input
  return false;
});

// Filter cluster items: use same word-overlap approach
clusters = clusters.filter(cl => {
  cl.items = (cl.items || []).filter(it => {
    const t = (it.item_text || it.suggested_title || '').toLowerCase().trim();
    if (actualInputs.some(inp => inp.includes(t) || t.includes(inp))) return true;
    if (wordOverlap(t) >= 0.25) return true;
    return false;
  });
  return cl.items.length > 0;
});

// ─── FIX 3: Build available_epics for epic <select> dropdowns ───
const available_epics = (epics.epics || []).map(e => {
  const openCount = e.artifacts.filter(a => {
    const as = (state.artifacts_status[a.artifact_id] || {}).status || 'unknown';
    return as === 'open' || as === 'committed';
  }).length;
  return { epic_id: e.epic_id, title: e.title, open_count: openCount };
});

// ─── ZERO-RESULT FALLBACK: If all AI output was hallucinated, create basic classifications ───
if (classifications.length === 0 && (pendingCtx.new_lines || []).length > 0) {
  const rawLines = pendingCtx.new_lines || [];
  // Split compound inputs and create portfolio classifications
  for (const line of rawLines) {
    // Split on common delimiters
    const parts = line.split(/,\s*(?:also\s+)?|;\s*|\s+and\s+(?=\w)/).map(p => p.trim()).filter(p => p.length > 3);
    for (const part of parts) {
      // Auto-capitalize first letter for title
      const title = part.charAt(0).toUpperCase() + part.slice(1);
      classifications.push({
        original_text: line,
        item_text: part,
        lane: 'portfolio',
        confidence: 0.5,
        portfolio_action: 'new_epic',
        epic_id: null,
        artifact_id: null,
        suggested_title: title,
        suggested_epic_title: title,
        suggested_type: 'small',
        suggested_xp: 3,
        reasoning: 'Auto-classified (AI output was invalid)'
      });
    }
  }
}

// Categorize items
const ops_admin_items = [];
const mastery_items = [];
const portfolio_mapped = [];
const pending_confirmations = [];
const cluster_confirmations = [];

let opsCount = 0, masteryCount = 0, portfolioExisting = 0, portfolioNewArt = 0, portfolioNewEpic = 0;

for (const c of classifications) {
  const item = {
    text: c.item_text || c.original_text || '',
    original_text: c.original_text || c.item_text || '',
    lane: c.lane || 'portfolio',
    confidence: c.confidence || 0.5,
    captured_at: isoNow,
    classified_at: isoNow,
    reasoning: c.reasoning || ''
  };

  if (c.lane === 'ops_admin') {
    opsCount++;
    ops_admin_items.push(item);
    if (!state.ops_log) state.ops_log = [];
    state.ops_log.push({ text: item.text, date: dateStr, status: 'open' });
  } else if (c.lane === 'mastery') {
    masteryCount++;
    mastery_items.push(item);
    if (!state.mastery_log) state.mastery_log = [];
    state.mastery_log.push({ text: item.text, date: dateStr, status: 'open' });
  } else {
    // Portfolio
    if (c.portfolio_action === 'existing_artifact' && c.artifact_id) {
      portfolioExisting++;
      portfolio_mapped.push({ text: item.text, artifact_id: c.artifact_id, epic_id: c.epic_id || '' });
      // Update last_touched
      if (state.artifacts_status[c.artifact_id]) {
        state.artifacts_status[c.artifact_id].last_touched = dateStr;
      }
      // ─── FIX 2 (existing matches): Add to pending_confirmations with action_to_confirm ───
      let artTitle = c.artifact_id;
      for (const ep of (epics.epics || [])) {
        const art = ep.artifacts.find(a => a.artifact_id === c.artifact_id);
        if (art) { artTitle = art.title; break; }
      }
      pending_confirmations.push({
        text: item.text,
        mode: 'existing_match',
        matched_epic_id: c.epic_id || '',
        matched_artifact_id: c.artifact_id,
        matched_title: artTitle,
        suggestion: 'Existing artifact: ' + artTitle + ' (' + (c.epic_id || '???') + ')',
        reasoning: c.reasoning || '',
        action_to_confirm: {
          cmd: 'sync',
          mappings: [{
            text: item.text,
            action: 'accept_existing',
            artifact_id: c.artifact_id,
            epic_id: c.epic_id || ''
          }]
        }
      });
    } else {
      // New artifact or new epic — needs confirmation
      if (c.portfolio_action === 'new_epic') portfolioNewEpic++;
      else portfolioNewArt++;

      // ─── FIX 2: Build action_to_confirm for each pending item ───
      const pendingItem = {
        text: item.text,
        suggestion: c.portfolio_action === 'new_epic'
          ? 'New epic: ' + (c.suggested_epic_title || c.suggested_title || item.text)
          : 'New artifact in ' + (c.epic_id || '???') + ': ' + (c.suggested_title || item.text) + ' (' + (c.suggested_type || 'small') + ', ' + (c.suggested_xp || 3) + ' XP)',
        portfolio_action: c.portfolio_action,
        epic_id: c.epic_id || null,
        suggested_title: c.suggested_title || item.text,
        suggested_epic_title: c.suggested_epic_title || null,
        suggested_type: c.suggested_type || 'small',
        suggested_xp: c.suggested_xp || 3,
        mode: c.portfolio_action === 'new_epic' ? 'new_epic' : 'new_artifact'
      };

      if (c.portfolio_action === 'new_epic') {
        pendingItem.action_to_confirm = {
          cmd: 'sync',
          mappings: [{
            text: item.text,
            action: 'create_epic',
            suggested_title: c.suggested_title || item.text,
            suggested_epic_title: c.suggested_epic_title || c.suggested_title || item.text,
            suggested_type: c.suggested_type || 'small',
            suggested_xp: c.suggested_xp || 3
          }]
        };
      } else {
        pendingItem.action_to_confirm = {
          cmd: 'sync',
          mappings: [{
            text: item.text,
            action: 'create_artifact',
            epic_id: c.epic_id || null,
            suggested_title: c.suggested_title || item.text,
            suggested_type: c.suggested_type || 'small',
            suggested_xp: c.suggested_xp || 3
          }]
        };
      }

      pending_confirmations.push(pendingItem);
    }
  }

  // Add to inbox_items in state
  if (!state.inbox_items) state.inbox_items = [];
  state.inbox_items.push(item);
}

// ─── FALLBACK: Auto-generate clusters if AI didn't produce them ───
// If there are new_epic or new_artifact items in pending_confirmations but no clusters,
// group them into clusters so the user sees proper cluster cards with accept buttons.
if (clusters.length === 0) {
  // Group pending items by suggested_epic_title or by new_epic/new_artifact
  const newEpicItems = pending_confirmations.filter(p => p.mode === 'new_epic');
  const newArtItems = pending_confirmations.filter(p => p.mode === 'new_artifact');

  // Group new_epic items by suggested_epic_title
  const epicGroups = {};
  for (const p of newEpicItems) {
    const key = p.suggested_epic_title || p.suggested_title || 'Untitled';
    if (!epicGroups[key]) epicGroups[key] = [];
    epicGroups[key].push(p);
  }

  let clusterIdx = 1;
  for (const [epicTitle, items] of Object.entries(epicGroups)) {
    clusters.push({
      cluster_id: 'C' + clusterIdx,
      suggested_epic_title: epicTitle,
      action: 'new_epic',
      epic_id: null,
      reasoning: 'Auto-grouped: ' + items.length + ' item(s) suggesting new epic "' + epicTitle + '"',
      items: items.map(it => ({
        item_text: it.text,
        suggested_title: it.suggested_title || it.text,
        suggested_type: it.suggested_type || 'small',
        suggested_xp: it.suggested_xp || 3
      })),
      suggested_artifacts: []
    });
    clusterIdx++;
  }

  // Also create single-item clusters for new_artifact items without a cluster
  for (const p of newArtItems) {
    if (!p.epic_id) {
      clusters.push({
        cluster_id: 'C' + clusterIdx,
        suggested_epic_title: p.suggested_title || p.text,
        action: 'new_epic',
        epic_id: null,
        reasoning: 'Auto-created: unclustered new artifact',
        items: [{
          item_text: p.text,
          suggested_title: p.suggested_title || p.text,
          suggested_type: p.suggested_type || 'small',
          suggested_xp: p.suggested_xp || 3
        }],
        suggested_artifacts: []
      });
      clusterIdx++;
    }
  }
}

// Process clusters
for (const cl of clusters) {
  const clusterItems = (cl.items || []).map(it => ({
    item_text: it.item_text || it.suggested_title || '',
    suggested_title: it.suggested_title || it.item_text || '',
    suggested_type: it.suggested_type || 'small',
    suggested_xp: it.suggested_xp || 3
  }));
  const totalXP = clusterItems.reduce((sum, it) => sum + (it.suggested_xp || 3), 0);

  // ─── FIX 1: Build accept_payload for cluster confirmation ───
  // Process suggested_artifacts for new epics (Feature 3: auto-suggest)
  const suggestedArtifacts = (cl.suggested_artifacts || []).map(sa => ({
    suggested_title: sa.suggested_title || '',
    suggested_type: sa.suggested_type || 'small',
    suggested_xp: sa.suggested_xp || 3,
    rationale: sa.rationale || ''
  }));

  // Build the accept mappings from cluster items
  const acceptMappings = clusterItems.map(it => ({
    text: it.item_text || it.suggested_title,
    action: 'create_epic_batch',
    epic_id: cl.epic_id || null,
    suggested_epic_title: cl.suggested_epic_title || 'Untitled Cluster',
    suggested_title: it.suggested_title,
    suggested_type: it.suggested_type || 'small',
    suggested_xp: it.suggested_xp || 3
  }));

  const accept_payload = {
    cmd: 'sync',
    mappings: acceptMappings
  };

  // Build accept_with_suggestions payload (includes AI-suggested artifacts)
  const acceptWithSuggestionsPayload = {
    cmd: 'sync',
    mappings: [
      ...acceptMappings,
      ...suggestedArtifacts.map(sa => ({
        text: sa.suggested_title,
        action: 'create_epic_batch',
        epic_id: cl.epic_id || null,
        suggested_epic_title: cl.suggested_epic_title || 'Untitled Cluster',
        suggested_title: sa.suggested_title,
        suggested_type: sa.suggested_type || 'small',
        suggested_xp: sa.suggested_xp || 3
      }))
    ]
  };

  cluster_confirmations.push({
    cluster_id: cl.cluster_id || 'C?',
    suggested_epic_title: cl.suggested_epic_title || 'Untitled Cluster',
    action: cl.action || 'new_epic',
    epic_id: cl.epic_id || null,
    reasoning: cl.reasoning || '',
    items: clusterItems,
    total_xp: totalXP,
    suggested_artifacts: suggestedArtifacts,
    accept_payload,
    accept_with_suggestions_payload: suggestedArtifacts.length > 0 ? acceptWithSuggestionsPayload : null
  });
}

// Save updated state
writeKV('pql:state:state_json', state);

const summary = {
  total_items: classifications.length,
  ops_admin: opsCount,
  mastery: masteryCount,
  portfolio_existing: portfolioExisting,
  portfolio_new_artifact: portfolioNewArt,
  portfolio_new_epic: portfolioNewEpic,
  clusters_found: clusters.length > 0 ? clusters.length : 0
};

return [{ json: {
  status: 'ok',
  cmd: 'sync',
  phase: 'ai_classified',
  date: dateStr,
  summary,
  available_epics,
  ops_admin_items,
  mastery_items,
  portfolio_mapped,
  pending_confirmations,
  cluster_confirmations
} }];

const fs = require('fs');
const pathMod = require('path');

const _raw = $input.first().json; const body = (typeof _raw.body === 'object' && _raw.body !== null && (_raw.body.cmd || _raw.body.action)) ? _raw.body : _raw;
const cmd = (body.cmd || 'unknown').toLowerCase().trim();
const free_text = body.free_text || '';
const now = new Date();
const isoNow = now.toISOString();
const dateStr = isoNow.slice(0, 10);

// ══════════════════════════════════════════════════════
// FILESYSTEM — Clean folder layout for browsing
// ══════════════════════════════════════════════════════
let PQL_DIR = '/tmp/pql';
const PQL_CANDIDATES = ['/home/node/.n8n/pql', '/root/.n8n/pql', '/data/pql'];
for (const candidate of PQL_CANDIDATES) {
  try {
    const parent = candidate.substring(0, candidate.lastIndexOf('/'));
    if (!fs.existsSync(parent)) continue;
    if (!fs.existsSync(candidate)) fs.mkdirSync(candidate, { recursive: true });
    const testFile = candidate + '/_writetest';
    fs.writeFileSync(testFile, 'ok', 'utf8');
    const readBack = fs.readFileSync(testFile, 'utf8');
    fs.unlinkSync(testFile);
    if (readBack === 'ok') { PQL_DIR = candidate; break; }
  } catch (e) { /* not writable, try next */ }
}
const BACKUP_DIR = pathMod.join(PQL_DIR, '_backups');
function ensureDir(d) { if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true }); }

function kvPath(key) {
  const STATIC = {
    'pql:library:epics_json':   'library/epics.json',
    'pql:state:state_json':     'state/state.json',
    'pql:inbox:scratchpad_md':  'inbox/scratchpad.md',
    'pql:sync:pending_context': 'state/sync_pending.json',
  };
  if (STATIC[key]) return pathMod.join(PQL_DIR, STATIC[key]);
  if (key.startsWith('pql:plans:weeks:')) return pathMod.join(PQL_DIR, 'plans', 'weeks', key.slice(16) + '.json');
  if (key.startsWith('pql:logs:daily:'))  return pathMod.join(PQL_DIR, 'logs',  'daily', key.slice(15) + '.json');
  if (key.startsWith('pql:outputs:status_email:')) return pathMod.join(PQL_DIR, 'outputs', 'status_email_' + key.slice(25) + '.json');
  return pathMod.join(PQL_DIR, '_misc', key.replace(/:/g, '_') + '.json');
}

function readKV(key) {
  const p = kvPath(key); if (!fs.existsSync(p)) return null;
  const raw = fs.readFileSync(p, 'utf8');
  try { return JSON.parse(raw); } catch { return raw; }
}

function writeKV(key, data) {
  const p = kvPath(key);
  const dir = pathMod.dirname(p);
  ensureDir(dir);
  if (fs.existsSync(p)) {
    ensureDir(BACKUP_DIR);
    const ext = pathMod.extname(p);
    const base = pathMod.basename(p, ext);
    fs.copyFileSync(p, pathMod.join(BACKUP_DIR, base + '_' + Date.now().toString(36) + ext));
  }
  fs.writeFileSync(p, typeof data === 'string' ? data : JSON.stringify(data, null, 2), 'utf8');
}

function listKVKeys() {
  const keys = [];
  const walk = (dir, prefix) => {
    if (!fs.existsSync(dir)) return;
    for (const f of fs.readdirSync(dir, { withFileTypes: true })) {
      if (f.name.startsWith('_')) continue;
      const full = pathMod.join(dir, f.name);
      if (f.isDirectory()) walk(full, prefix + f.name + '/');
      else keys.push(prefix + f.name);
    }
  };
  walk(PQL_DIR, '');
  return keys;
}

(function migrateOldKV() {
  const oldMarker = pathMod.join(PQL_DIR, '_migrated_v5');
  if (fs.existsSync(oldMarker)) return;
  const OLD_MAP = {
    'pql__library__epics_json.json':        'pql:library:epics_json',
    'pql__state__state_json.json':          'pql:state:state_json',
    'pql__inbox__scratchpad_md.json':       'pql:inbox:scratchpad_md',
    'pql__sync__pending_context.json':      'pql:sync:pending_context',
  };
  let migrated = 0;
  for (const [oldFile, key] of Object.entries(OLD_MAP)) {
    const oldPath = pathMod.join(PQL_DIR, oldFile);
    if (fs.existsSync(oldPath)) {
      const newPath = kvPath(key);
      ensureDir(pathMod.dirname(newPath));
      fs.copyFileSync(oldPath, newPath);
      migrated++;
    }
  }
  if (fs.existsSync(PQL_DIR)) {
    for (const f of fs.readdirSync(PQL_DIR)) {
      if (!f.endsWith('.json') || !f.startsWith('pql__')) continue;
      const oldKey = f.replace('.json', '').replace(/__/g, ':');
      if (OLD_MAP[f]) continue;
      const oldPath = pathMod.join(PQL_DIR, f);
      const newPath = kvPath(oldKey);
      if (newPath !== oldPath) {
        ensureDir(pathMod.dirname(newPath));
        fs.copyFileSync(oldPath, newPath);
        migrated++;
      }
    }
  }
  if (migrated > 0) {
    try { fs.writeFileSync(oldMarker, 'migrated ' + migrated + ' files at ' + new Date().toISOString(), 'utf8'); } catch {}
  }
})();
function getWeekId(d) {
  const dt = new Date(d); dt.setHours(0,0,0,0);
  const thu = new Date(dt); thu.setDate(dt.getDate() + 3 - ((dt.getDay()+6)%7));
  const ys = new Date(thu.getFullYear(),0,1);
  return thu.getFullYear() + '-W' + String(Math.ceil((((thu-ys)/86400000)+1)/7)).padStart(2,'0');
}
function buildArtLookup(epics) {
  const m = {};
  if (epics && epics.epics) { for (const e of epics.epics) { for (const a of e.artifacts) { m[a.artifact_id] = { title: a.title, xp: a.xp, type: a.type, epic_id: e.epic_id, epic_title: e.title, milestone_id: a.milestone_id }; } } }
  return m;
}
const weekId = getWeekId(now);

function checkEpicCompletion(state, epics, epicId, dateStr) {
  const epic = epics.epics.find(e => e.epic_id === epicId);
  if (!epic) return null;
  if (state.epics_status[epicId] === 'completed') return null;
  const nonBonusArts = epic.artifacts.filter(a => a.type !== 'bonus');
  if (nonBonusArts.length === 0) return null;
  const allShipped = nonBonusArts.every(a => {
    const st = state.artifacts_status[a.artifact_id];
    return st && st.status === 'shipped';
  });
  if (!allShipped) return null;
  const bonusArtId = epicId + '-BONUS';
  if (state.artifacts_status[bonusArtId]) return null;
  const bonusArt = {
    artifact_id: bonusArtId,
    title: epic.title + ' — Epic Complete!',
    xp: 5,
    type: 'bonus',
    milestone_id: epic.milestones.length > 0
      ? epic.milestones[epic.milestones.length - 1].milestone_id
      : epicId + '-M1',
    default_status: 'shipped'
  };
  epic.artifacts.push(bonusArt);
  if (epic.milestones.length > 0) {
    const lastMs = epic.milestones[epic.milestones.length - 1];
    if (!lastMs.artifacts.includes(bonusArtId)) lastMs.artifacts.push(bonusArtId);
  }
  state.artifacts_status[bonusArtId] = {
    epic_id: epicId,
    status: 'shipped',
    last_touched: dateStr,
    shipped_dates: [dateStr],
    dependency: { exists: false, waiting_on: '', ping_date: '', notes: '' }
  };
  state.epics_status[epicId] = 'completed';
  const entry = {
    date: dateStr,
    artifact_id: bonusArtId,
    epic_id: epicId,
    xp: 5,
    note: 'EPIC COMPLETE: ' + epic.title
  };
  state.xp_ledger.push(entry);
  return { bonusArtId, epic_title: epic.title, xp: 5, entry };
}

function checkAllEpicCompletions(state, epics, shippedEpicIds, dateStr) {
  const bonuses = [];
  const uniqueEpicIds = [...new Set(shippedEpicIds)];
  for (const eid of uniqueEpicIds) {
    const bonus = checkEpicCompletion(state, epics, eid, dateStr);
    if (bonus) bonuses.push(bonus);
  }
  return bonuses;
}

function computePace(state) {
  const ledger = state.xp_ledger || [];
  const weeklyXP = {};
  const weekShipDays = {};
  for (const entry of ledger) {
    const wk = getWeekId(new Date(entry.date));
    weeklyXP[wk] = (weeklyXP[wk] || 0) + entry.xp;
    if (!weekShipDays[wk]) weekShipDays[wk] = new Set();
    weekShipDays[wk].add(entry.date);
  }
  const thisWeekXP = weeklyXP[weekId] || 0;
  const thisWeekShipDays = weekShipDays[weekId] ? weekShipDays[weekId].size : 0;
  const thisWeekShipDates = weekShipDays[weekId] ? Array.from(weekShipDays[weekId]).sort() : [];
  const streakCutoff = new Date(now); streakCutoff.setDate(streakCutoff.getDate() - 28);
  const streakCutoffStr = streakCutoff.toISOString().slice(0, 10);
  const streakShipDates = []; for (const dates of Object.values(weekShipDays)) { for (const d of dates) { if (d >= streakCutoffStr) streakShipDates.push(d); } }
  // Also include shipped_dates from artifacts_status (covers pre-fix backfills missing ledger entries)
  const streakSet = new Set(streakShipDates);
  for (const a of Object.values(state.artifacts_status || {})) {
    for (const sd of (a.shipped_dates || [])) {
      if (sd >= streakCutoffStr && !streakSet.has(sd)) { streakShipDates.push(sd); streakSet.add(sd); }
    }
  }
  const priorWeeks = Object.keys(weeklyXP).filter(w => w < weekId).sort().reverse().slice(0, 3);
  const priorXPs = priorWeeks.map(w => weeklyXP[w] || 0);
  let baseline = 0;
  if (priorXPs.length > 0) {
    const sorted = [...priorXPs].sort((a, b) => a - b);
    const mid = Math.floor(sorted.length / 2);
    baseline = sorted.length % 2 === 0 ? Math.round((sorted[mid - 1] + sorted[mid]) / 2) : sorted[mid];
  }
  const minThreshold = Math.round(baseline * 0.8);
  const aheadThreshold = Math.round(baseline * 1.2);
  let pace = 'on_track';
  if (baseline === 0) {
    pace = thisWeekXP > 0 ? 'ahead' : 'no_baseline';
  } else if (thisWeekXP >= aheadThreshold) {
    pace = 'ahead';
  } else if (thisWeekXP < minThreshold) {
    pace = 'lagging';
  }
  const shipDayHealthy = thisWeekShipDays >= 3;
  if (pace === 'on_track' && !shipDayHealthy && thisWeekShipDays > 0 && thisWeekXP > 0) {
    pace = 'lagging';
  }
  return {
    this_week_xp: thisWeekXP,
    baseline_xp: baseline,
    min_threshold: minThreshold,
    ahead_threshold: aheadThreshold,
    pace,
    prior_weeks: priorWeeks.map(w => ({ week: w, xp: weeklyXP[w] || 0 })),
    ship_days: thisWeekShipDays,
    ship_dates: thisWeekShipDates,
    streak_ship_dates: streakShipDates.sort(),
    ship_day_target: 3,
    ship_day_healthy: shipDayHealthy,
    weekly_history: Object.keys(weeklyXP).sort().map(w => ({
      week: w, xp: weeklyXP[w], ship_days: weekShipDays[w] ? weekShipDays[w].size : 0
    }))
  };
}

