function handleInit() {
  const force = body.force === true;
  const existing_state = readKV('pql:state:state_json');
  const existing_epics = readKV('pql:library:epics_json');
  const healthy = existing_state && existing_epics && existing_epics.epics && existing_state.artifacts_status;

  if (healthy && !force) {
    const artCount = Object.keys(existing_state.artifacts_status).length;
    const epicCount = existing_epics.epics.length;
    return [{ json: { status: 'ok', cmd: 'init', result: 'already_initialized', message: 'Healthy data found: ' + epicCount + ' epics, ' + artCount + ' artifacts. Use /sync to add work. Send {"cmd":"init","force":true} to wipe and restart.', storage_path: PQL_DIR, artifact_count: artCount, epic_count: epicCount } }];
  }

  const reason = force ? 'force reinit' : (!existing_state && !existing_epics) ? 'no data' : 'partial/corrupt data repaired';
  const emptyEpics = { epics: [] };
  const emptyState = { current_date: dateStr, current_week_id: weekId, epics_status: {}, artifacts_status: {}, weekly: { week_id: weekId, quests: [], moves: [], committed_artifacts: [], stretch_artifacts: [], parked_artifacts: [], pings_due: [] }, xp_ledger: [], inbox_items: [] };
  const wp = { week_id: weekId, created_at: isoNow, quests: [], moves: [], committed_artifacts: [], stretch_artifacts: [], parked_artifacts: [], pings_due: [] };
  writeKV('pql:library:epics_json', emptyEpics);
  writeKV('pql:state:state_json', emptyState);
  writeKV('pql:inbox:scratchpad_md', 'PQL Scratchpad created ' + isoNow);
  writeKV('pql:plans:weeks:' + weekId, wp);
  return [{ json: { status: 'ok', cmd: 'init', result: 'initialized', reason: reason, date: dateStr, week: weekId, storage_path: PQL_DIR, message: 'Empty portfolio created (' + reason + '). Use /sync to brain dump your first tasks.' } }];
}


