// /start
// ══════════════════════════════════════════════════════
function handleStart() {
  const state = readKV('pql:state:state_json');
  const epics = readKV('pql:library:epics_json');
  if (!state || !epics) return [{ json: { status: 'error', cmd: 'start', message: 'No data. Run /init first. Storage: ' + PQL_DIR, storage_path: PQL_DIR } }];
  const artLookup = buildArtLookup(epics);
  const phase = body.phase || 'review';

  if (free_text) {
    let sp = readKV('pql:inbox:scratchpad_md') || '';
    sp += '\n[' + isoNow + '] ' + free_text;
    writeKV('pql:inbox:scratchpad_md', sp);
  }

  if (phase === 'review') {
    const fiveDaysAgo = new Date(now); fiveDaysAgo.setDate(fiveDaysAgo.getDate() - 5);
    const agingDateStr = fiveDaysAgo.toISOString().slice(0,10);
    const allArts = []; const agingArts = []; const depsArts = []; const noDepsArts = [];
    for (const aid of Object.keys(state.artifacts_status)) {
      const a = state.artifacts_status[aid]; const info = artLookup[aid] || {};
      const item = { artifact_id: aid, title: info.title || aid, type: info.type || '?', xp: info.xp || 0, status: a.status, epic_id: a.epic_id, epic_title: info.epic_title || '', last_touched: a.last_touched, dependency: a.dependency };
      if (a.status === 'shipped') continue;
      allArts.push(item);
      const isAging = (a.last_touched <= agingDateStr);
      const pingOverdue = (a.dependency && a.dependency.exists && a.dependency.ping_date && a.dependency.ping_date <= dateStr);
      if (isAging || pingOverdue) agingArts.push({ ...item, aging_reason: isAging ? 'not_touched_5d' : 'ping_overdue' });
      if (a.dependency && a.dependency.exists) depsArts.push(item); else noDepsArts.push(item);
    }
    const epicsSummary = [];
    for (const e of epics.epics) {
      const es = state.epics_status[e.epic_id] || 'inactive';
      const arts = e.artifacts.map(a => ({ artifact_id: a.artifact_id, title: a.title, status: (state.artifacts_status[a.artifact_id] || {}).status || 'unknown' }));
      epicsSummary.push({ epic_id: e.epic_id, title: e.title, status: es, artifacts: arts });
    }
    if (!state.ops_log) state.ops_log = [];
    { const usedIds = new Set(state.ops_log.filter(o => o.id).map(o => o.id)); let counter = state.ops_log.length; for (const o of state.ops_log) { if (!o.id) { let nid; do { counter++; nid = 'OPS-' + String(counter).padStart(3,'0'); } while (usedIds.has(nid)); o.id = nid; usedIds.add(nid); } if (o.waiting_on === undefined) o.waiting_on = ''; if (o.ping_date === undefined) o.ping_date = ''; } }
    const overdueOps = state.ops_log.filter(o => o.status === 'open' && o.ping_date && o.ping_date <= dateStr);

    return [{ json: { status: 'ok', cmd: 'start', phase: 'review', date: dateStr, week_id: weekId, message: 'Review your portfolio. Then send phase=plan with your selections.', brain_dump_captured: !!free_text, epics: epicsSummary, aging_artifacts: agingArts, aging_count: agingArts.length, artifacts_with_dependencies: depsArts, artifacts_without_dependencies: noDepsArts, all_open_artifacts: allArts, open_count: allArts.length, overdue_ops_pings: overdueOps, overdue_ops_count: overdueOps.length, pace: computePace(state), next_step: { phase: 'plan', required_fields: { shipped: 'array of artifact_ids shipped since last plan', committed: 'array of artifact_ids to commit this week', stretch: 'array of artifact_ids as stretch goals', parked: 'array of artifact_ids to park', quests: 'array of 2 objects: [{epic_id, friday_artifact_id}]', dependencies: 'array of {artifact_id, waiting_on, ping_date, notes}' } } } }];
  }

  if (phase === 'plan') {
    const shipped = body.shipped || []; const leverageTypes = body.leverage_types || {}; const shipResults = []; let xpEarned = 0;
    const shippedEpicIds = [];
    for (const aid of shipped) { const a = state.artifacts_status[aid]; if (!a || a.status === 'shipped') continue; const info = artLookup[aid] || {}; a.status = 'shipped'; a.last_touched = dateStr; a.shipped_dates.push(dateStr); const xp = info.xp || 0; xpEarned += xp; const levType = leverageTypes[aid] || null; if (levType) { a.leverage_type = levType; } state.xp_ledger.push({ date: dateStr, artifact_id: aid, epic_id: a.epic_id, xp, note: 'Shipped: ' + (info.title || aid), leverage_type: levType }); shipResults.push({ artifact_id: aid, xp, leverage_type: levType }); shippedEpicIds.push(a.epic_id); }
    const epicBonuses = checkAllEpicCompletions(state, epics, shippedEpicIds, dateStr);
    for (const b of epicBonuses) { xpEarned += b.xp; shipResults.push({ artifact_id: b.bonusArtId, xp: b.xp, action: 'epic_bonus', epic_title: b.epic_title }); }
    if (epicBonuses.length > 0) writeKV('pql:library:epics_json', epics);
    const deps = body.dependencies || [];
    for (const d of deps) { const a = state.artifacts_status[d.artifact_id]; if (a) { a.dependency = { exists: true, waiting_on: d.waiting_on || '', ping_date: d.ping_date || '', notes: d.notes || '' }; } }
    const committed = body.committed || []; const stretch = body.stretch || []; const parked = body.parked || [];
    for (const aid of committed) { if (state.artifacts_status[aid]) { state.artifacts_status[aid].status = 'committed'; state.artifacts_status[aid].last_touched = dateStr; } }
    for (const aid of stretch) { if (state.artifacts_status[aid]) { state.artifacts_status[aid].status = 'stretch'; state.artifacts_status[aid].last_touched = dateStr; } }
    for (const aid of parked) { if (state.artifacts_status[aid]) { state.artifacts_status[aid].status = 'parked'; state.artifacts_status[aid].last_touched = dateStr; } }
    const questsInput = body.quests || []; const quests = [];
    for (let i = 0; i < Math.min(questsInput.length, 2); i++) { const q = questsInput[i]; quests.push({ quest_id: 'Q' + (i+1), epic_id: q.epic_id, friday_finishline_artifact_id: q.friday_artifact_id }); }
    const moves = [];
    if (quests[0]) { const info = artLookup[quests[0].friday_finishline_artifact_id] || {}; moves.push({ move_id: 'M1', description: 'Produce Friday finish line for Q1: ' + (info.title || quests[0].friday_finishline_artifact_id), linked_artifact_ids: [quests[0].friday_finishline_artifact_id] }); }
    if (quests[1]) { const info = artLookup[quests[1].friday_finishline_artifact_id] || {}; moves.push({ move_id: 'M2', description: 'Produce Friday finish line for Q2: ' + (info.title || quests[1].friday_finishline_artifact_id), linked_artifact_ids: [quests[1].friday_finishline_artifact_id] }); }
    const questArtIds = quests.map(q => q.friday_finishline_artifact_id);
    const m3c = committed.filter(aid => !questArtIds.includes(aid)).map(aid => ({ aid, xp: (artLookup[aid] || {}).xp || 0 })).sort((a,b) => b.xp - a.xp);
    if (m3c.length > 0) { const t = m3c[0]; const info = artLookup[t.aid] || {}; moves.push({ move_id: 'M3', description: 'Critical prerequisite: ' + (info.title || t.aid), linked_artifact_ids: [t.aid] }); }
    else if (committed.length > 0) { const fb = committed[0]; const info = artLookup[fb] || {}; moves.push({ move_id: 'M3', description: 'Advance: ' + (info.title || fb), linked_artifact_ids: [fb] }); }
    const pings = []; const weekEnd = new Date(now); weekEnd.setDate(weekEnd.getDate() + (5 - weekEnd.getDay())); const weekEndStr = weekEnd.toISOString().slice(0,10);
    for (const aid of Object.keys(state.artifacts_status)) { const a = state.artifacts_status[aid]; if (a.dependency && a.dependency.exists && a.dependency.ping_date && a.dependency.ping_date <= weekEndStr) { pings.push({ artifact_id: aid, ping_date: a.dependency.ping_date, waiting_on: a.dependency.waiting_on }); } }
    const weekPlan = { week_id: weekId, created_at: isoNow, quests, moves, committed_artifacts: committed, stretch_artifacts: stretch, parked_artifacts: parked, pings_due: pings };
    state.weekly = weekPlan; state.current_date = dateStr; state.current_week_id = weekId;
    writeKV('pql:plans:weeks:' + weekId, weekPlan);
    writeKV('pql:state:state_json', state);
    return [{ json: { status: 'ok', cmd: 'start', phase: 'plan_saved', date: dateStr, week_id: weekId, ships_processed: shipResults, xp_earned: xpEarned, epic_bonuses: epicBonuses.map(b => ({ epic_id: b.entry.epic_id, epic_title: b.epic_title, bonus_xp: b.xp })), quests, moves, committed_artifacts: committed, stretch_artifacts: stretch, parked_artifacts: parked, pings_due: pings, pace: computePace(state) } }];
  }
  return [{ json: { status: 'error', cmd: 'start', message: 'Unknown phase: ' + phase } }];
}

