// /sync — BUILD AI REQUEST
// ══════════════════════════════════════════════════════
function handleSync() {
  const state = readKV('pql:state:state_json');
  if (!state) return [{ json: { _route: 'direct', status: 'error', cmd: 'sync', message: 'No state. Run seed first.' } }];
  const epics = readKV('pql:library:epics_json');
  if (!epics) return [{ json: { _route: 'direct', status: 'error', cmd: 'sync', message: 'No epics. Run seed first.' } }];

  const mappings = body.mappings || [];
  if (mappings.length > 0) {
    const results = [];
    for (const m of mappings) {
      if (m.action === 'accept' || m.action === 'mapped') {
        const idx = (state.inbox_items || []).findIndex(i => i.text === m.text);
        if (idx >= 0) { state.inbox_items[idx].mapped_to = { epic_id: m.epic_id, artifact_id: m.artifact_id, action: 'mapped' }; state.inbox_items[idx].suggested_lane = m.lane || state.inbox_items[idx].suggested_lane; }
        results.push({ text: m.text, action: 'mapped', epic_id: m.epic_id, artifact_id: m.artifact_id });
      } else if (m.action === 'accept_existing') {
        const aid = m.artifact_id;
        const eid = m.epic_id;
        if (aid && state.artifacts_status[aid]) {
          state.artifacts_status[aid].last_touched = dateStr;
          let artTitle = aid;
          for (const ep of (epics.epics || [])) {
            const art = ep.artifacts.find(a => a.artifact_id === aid);
            if (art) { artTitle = art.title; break; }
          }
          results.push({ action: 'accepted_existing', artifact_id: aid, epic_id: eid, title: artTitle, text: m.text });
        }
      } else if (m.action === 'create_artifact') {
        const epic = epics.epics.find(e => e.epic_id === m.epic_id);
        if (epic) {
          const newArtId = m.epic_id + '-A' + (epic.artifacts.length + 1);
          const artType = m.suggested_type || 'small';
          const xpMap = { slice: 2, small: 3, medium: 8, large: 12 };
          const xp = m.suggested_xp || xpMap[artType] || 3;
          const lastMs = epic.milestones[epic.milestones.length - 1];
          epic.artifacts.push({ artifact_id: newArtId, title: m.suggested_title || m.text, xp, type: artType, milestone_id: lastMs ? lastMs.milestone_id : m.epic_id + '-M1', default_status: 'open' });
          if (lastMs) lastMs.artifacts.push(newArtId);
          state.artifacts_status[newArtId] = { epic_id: m.epic_id, status: 'open', last_touched: dateStr, shipped_dates: [], dependency: { exists: false, waiting_on: '', ping_date: '', notes: '' } };
          const idx = (state.inbox_items || []).findIndex(i => i.text === m.text);
          if (idx >= 0) state.inbox_items[idx].mapped_to = { epic_id: m.epic_id, artifact_id: newArtId, action: 'created' };
          results.push({ text: m.text, action: 'artifact_created', epic_id: m.epic_id, artifact_id: newArtId, title: m.suggested_title || m.text, xp, type: artType });
        }
      } else if (m.action === 'create_epic') {
        const epicNum = epics.epics.length + 1;
        const newEpicId = 'EPIC-' + String(epicNum).padStart(3, '0');
        const newMsId = newEpicId + '-M1';
        const newArtId = newEpicId + '-A1';
        const artType = m.suggested_type || 'small';
        const xpMap = { slice: 2, small: 3, medium: 8, large: 12 };
        const xp = m.suggested_xp || xpMap[artType] || 3;
        epics.epics.push({ epic_id: newEpicId, title: m.suggested_epic_title || m.suggested_title || m.text, description: m.description || 'Created from brain dump', milestones: [{ milestone_id: newMsId, title: 'Draft', artifacts: [newArtId] }], artifacts: [{ artifact_id: newArtId, title: m.suggested_title || m.text, xp, type: artType, milestone_id: newMsId, default_status: 'open' }] });
        state.epics_status[newEpicId] = 'active';
        state.artifacts_status[newArtId] = { epic_id: newEpicId, status: 'open', last_touched: dateStr, shipped_dates: [], dependency: { exists: false, waiting_on: '', ping_date: '', notes: '' } };
        const idx = (state.inbox_items || []).findIndex(i => i.text === m.text);
        if (idx >= 0) state.inbox_items[idx].mapped_to = { epic_id: newEpicId, artifact_id: newArtId, action: 'created_epic' };
        results.push({ text: m.text, action: 'epic_created', epic_id: newEpicId, artifact_id: newArtId, title: m.suggested_epic_title || m.text, xp, type: artType });
      } else if (m.action === 'create_epic_batch') {
        const xpMap = { slice: 2, small: 3, medium: 8, large: 12 };
        let targetEpicId = m.epic_id;
        let targetEpic = targetEpicId ? epics.epics.find(e => e.epic_id === targetEpicId) : null;
        if (!targetEpic && m.suggested_epic_title) {
          const epicNum = epics.epics.length + 1;
          targetEpicId = 'EPIC-' + String(epicNum).padStart(3, '0');
          const msId = targetEpicId + '-M1';
          targetEpic = { epic_id: targetEpicId, title: m.suggested_epic_title, description: 'Created from brain dump cluster', milestones: [{ milestone_id: msId, title: 'Draft', artifacts: [] }], artifacts: [] };
          epics.epics.push(targetEpic);
          state.epics_status[targetEpicId] = 'active';
          results.push({ text: m.suggested_epic_title, action: 'epic_created', epic_id: targetEpicId, title: m.suggested_epic_title });
          for (let bi = mappings.indexOf(m) + 1; bi < mappings.length; bi++) {
            if (mappings[bi].action === 'create_epic_batch' && mappings[bi].suggested_epic_title === m.suggested_epic_title) {
              mappings[bi].epic_id = targetEpicId;
            }
          }
        }
        if (targetEpic) {
          const artNum = targetEpic.artifacts.length + 1;
          const newArtId = targetEpicId + '-A' + artNum;
          const artType = m.suggested_type || 'small';
          const xp = m.suggested_xp || xpMap[artType] || 3;
          const lastMs = targetEpic.milestones[targetEpic.milestones.length - 1];
          targetEpic.artifacts.push({ artifact_id: newArtId, title: m.suggested_title || m.text, xp, type: artType, milestone_id: lastMs ? lastMs.milestone_id : targetEpicId + '-M1', default_status: 'open' });
          if (lastMs) lastMs.artifacts.push(newArtId);
          state.artifacts_status[newArtId] = { epic_id: targetEpicId, status: 'open', last_touched: dateStr, shipped_dates: [], dependency: { exists: false, waiting_on: '', ping_date: '', notes: '' } };
          const idx = (state.inbox_items || []).findIndex(i => i.text === m.text);
          if (idx >= 0) state.inbox_items[idx].mapped_to = { epic_id: targetEpicId, artifact_id: newArtId, action: 'created_in_cluster' };
          results.push({ text: m.text, action: 'artifact_created', epic_id: targetEpicId, artifact_id: newArtId, title: m.suggested_title || m.text, xp, type: artType });
        }
      }
    }
    writeKV('pql:library:epics_json', epics);
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'sync', phase: 'mappings_applied', date: dateStr, results, total_epics: epics.epics.length, total_artifacts: Object.keys(state.artifacts_status).length } }];
  }

  const scratchpad = readKV('pql:inbox:scratchpad_md') || '';
  const lines = scratchpad.split('\n').filter(l => l.trim().length > 0);
  const processedTextsSet = new Set();
  for (const i of (state.inbox_items || [])) {
    if (i.text) processedTextsSet.add(i.text);
    if (i.original_text) processedTextsSet.add(i.original_text);
  }
  const processedTexts = { includes: (t) => processedTextsSet.has(t) };
  const newLines = [];
  for (const line of lines) {
    const cleaned = line.replace(/^\[.*?\]\s*/, '').trim();
    if (!cleaned || cleaned.startsWith('#') || cleaned.startsWith('PQL Scratchpad')) continue;
    if (!processedTexts.includes(cleaned)) newLines.push(cleaned);
  }
  if (free_text && free_text.trim().length > 0 && !processedTexts.includes(free_text.trim())) {
    newLines.push(free_text.trim());
    let sp = readKV('pql:inbox:scratchpad_md') || '';
    sp += '\n[' + isoNow + '] ' + free_text.trim();
    writeKV('pql:inbox:scratchpad_md', sp);
  }

  if (newLines.length === 0) {
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'sync', date: dateStr, message: 'No new items to process.', total_inbox_items: (state.inbox_items || []).length } }];
  }

  let epicsCtx = '';
  for (const e of epics.epics) {
    const es = state.epics_status[e.epic_id] || 'inactive';
    const openArts = e.artifacts.filter(a => { const s = (state.artifacts_status[a.artifact_id] || {}).status; return s === 'open' || s === 'committed'; });
    const shippedCount = e.artifacts.filter(a => (state.artifacts_status[a.artifact_id] || {}).status === 'shipped').length;
    epicsCtx += '\nEpic: ' + e.epic_id + ' — ' + e.title + ' [' + es + ', ' + e.artifacts.length + ' artifacts, ' + shippedCount + ' shipped]\n';
    // Show up to 5 key artifacts for matching context
    const sample = openArts.slice(0, 5);
    for (const a of sample) {
      epicsCtx += '  - ' + a.artifact_id + ': ' + a.title + ' (' + a.type + ')\n';
    }
    if (openArts.length > 5) epicsCtx += '  ... and ' + (openArts.length - 5) + ' more open artifacts\n';
  }

  let itemsList = '';
  for (let i = 0; i < newLines.length; i++) {
    itemsList += (i + 1) + '. "' + newLines[i].replace(/"/g, '\\"') + '"\n';
  }

  const sysPrompt = 'You are a classifier for a Portfolio Quest League productivity system. Respond ONLY with valid JSON, no markdown fences, no explanation.';

  const userPrompt = `You MUST classify ONLY these exact items (do NOT invent new items):

ITEMS TO CLASSIFY:
${itemsList}

Classify each item above into lanes and cluster related portfolio items. THREE parts:

PART 1 — CLASSIFY each item into a lane:
- "ops_admin": emails, calls, scheduling, meetings, follow-ups, admin, logistics, tool setup
- "mastery": learning without tangible output: tutorials, courses, reading, training
- "portfolio": work producing a TANGIBLE DELIVERABLE (doc, deck, script, dashboard, analysis, memo, framework). Must answer: "What file/deliverable will exist when done?"
NOT portfolio: "Read X", "Study X", "Set up X", "Meet with X" (unless they explicitly mention producing output)

For portfolio items determine: "existing_artifact" (matches below), "new_artifact" (fits existing epic), or "new_epic" (no matching epic).

Artifact sizing: slice (2 XP, minimal output), small (3 XP, complete limited scope), medium (8 XP, substantial), large (12 XP, polished final package).
Title format: "[Verb] [Specific Deliverable] for/of [Context]" — e.g. "Draft Stakeholder Analysis for Water Project"

PART 2 — CLUSTER related portfolio items:
- 2+ items sharing a theme that matches an existing epic → cluster with "existing_epic"
- 2+ items sharing a theme with NO matching epic → cluster with "new_epic"
- Single new_epic item → its own cluster
- Items with "existing_artifact" do NOT go in clusters

PART 3 — For each "new_epic" cluster, add "suggested_artifacts" (3-6) showing the progression:
1. Planning/scoping artifact (outline, framework)
2. Core production artifacts (drafts, analyses)
3. Completion artifact (final deliverable, presentation)

CURRENT EPICS:
${epicsCtx}

REMINDER: Classify ONLY the items listed at the top. Do NOT add items that are not in the list.

Return ONLY valid JSON (no markdown fences):
{"classifications":[{"original_text":"exact input text","item_text":"individual task after splitting","lane":"ops_admin|mastery|portfolio","confidence":0.85,"portfolio_action":"existing_artifact|new_artifact|new_epic|null","epic_id":"EPIC-XXX or null","artifact_id":"ID or null","suggested_title":"title or null","suggested_epic_title":"epic title or null","suggested_type":"slice|small|medium|large|null","suggested_xp":3,"reasoning":"1-line explanation"}],"clusters":[{"cluster_id":"C1","suggested_epic_title":"title","action":"new_epic|existing_epic","epic_id":"EPIC-XXX or null","reasoning":"why grouped","items":[{"item_text":"text","suggested_title":"title","suggested_type":"slice|small|medium|large","suggested_xp":3}],"suggested_artifacts":[{"suggested_title":"title","suggested_type":"small|medium|large","suggested_xp":3,"rationale":"why needed"}]}]}`;

  writeKV('pql:sync:pending_context', {
    new_lines: newLines, date: dateStr, iso_now: isoNow, week_id: weekId
  });

  return [{ json: {
    _route: 'ai',
    cmd: 'sync',
    items_count: newLines.length,
    new_lines: newLines,
    chatInput: userPrompt,
    ai_system: sysPrompt
  } }];
}

// ══════════════════════════════════════════════════════
// /week
// ══════════════════════════════════════════════════════
function handleWeek() {
  const plan = readKV('pql:plans:weeks:' + weekId);
  const state = readKV('pql:state:state_json');
  const epics = readKV('pql:library:epics_json');
  if (!plan && !state) return [{ json: { _route: 'direct', status: 'error', cmd: 'week', message: 'No data. Run /seed then /start first.' } }];

  const src = (plan && plan.quests && plan.quests.length > 0) ? plan
            : (state && state.weekly && state.weekly.quests && state.weekly.quests.length > 0) ? state.weekly
            : null;

  if (!src || !src.quests || src.quests.length === 0) {
    const artLookup = buildArtLookup(epics);
    const openArts = [];
    if (state && state.artifacts_status) {
      for (const aid of Object.keys(state.artifacts_status)) {
        const a = state.artifacts_status[aid];
        if (a.status !== 'shipped' && a.status !== 'parked') {
          const info = artLookup[aid] || {};
          openArts.push({ artifact_id: aid, title: info.title || aid, type: info.type || '?', xp: info.xp || 0, status: a.status, epic_id: a.epic_id, epic_title: info.epic_title || '' });
        }
      }
    }
    const epicIds = [...new Set(openArts.map(a => a.epic_id))];
    const exampleQuests = [];
    for (let i = 0; i < Math.min(epicIds.length, 2); i++) {
      const eArts = openArts.filter(a => a.epic_id === epicIds[i]);
      if (eArts.length > 0) {
        exampleQuests.push({ epic_id: epicIds[i], friday_artifact_id: eArts[0].artifact_id });
      }
    }
    const exampleCommitted = openArts.slice(0, 3).map(a => a.artifact_id);

    return [{ json: {
      status: 'ok', cmd: 'week', week_id: weekId,
      empty: true,
      message: 'No weekly plan set yet. Run /start, then send a plan payload to set your quests and commitments.',
      open_artifacts: openArts,
      open_count: openArts.length,
      plan_template: {
        cmd: 'start',
        phase: 'plan',
        shipped: [],
        committed: exampleCommitted,
        stretch: [],
        parked: [],
        quests: exampleQuests,
        dependencies: []
      }
    } }];
  }

  const artLookup = buildArtLookup(epics);
  function enrich(ids) { return (ids || []).map(aid => { const info = artLookup[aid] || {}; const st = state ? (state.artifacts_status[aid] || {}) : {}; return { artifact_id: aid, title: info.title || aid, type: info.type || '?', xp: info.xp || 0, status: st.status || 'unknown', epic_title: info.epic_title || '', parked_waiting_on: st.parked_waiting_on || '' }; }); }
  const pace = computePace(state);
  // Compute unplanned artifacts: open/committed in state but not in any weekly plan list
  const plannedIds = new Set([...(src.committed_artifacts || []), ...(src.stretch_artifacts || []), ...(src.parked_artifacts || [])]);
  const unplanned = [];
  if (state && state.artifacts_status) {
    for (const aid of Object.keys(state.artifacts_status)) {
      const a = state.artifacts_status[aid];
      if (a.status !== 'shipped' && a.status !== 'parked' && !plannedIds.has(aid)) {
        const info = artLookup[aid] || {};
        unplanned.push({ artifact_id: aid, title: info.title || aid, type: info.type || '?', xp: info.xp || 0, status: a.status || 'open', epic_id: a.epic_id, epic_title: info.epic_title || '' });
      }
    }
  }
  return [{ json: { status: 'ok', cmd: 'week', week_id: weekId, quests: src.quests, quests_count: (src.quests||[]).length, moves: src.moves || [], moves_count: (src.moves||[]).length, committed: enrich(src.committed_artifacts), stretch: enrich(src.stretch_artifacts), parked: enrich(src.parked_artifacts), unplanned, unplanned_count: unplanned.length, pings_due: src.pings_due || [], pace } }];
}

