// /status
// ══════════════════════════════════════════════════════
function handleStatus() {
  const state = readKV('pql:state:state_json');
  const epics = readKV('pql:library:epics_json');
  if (!state || !epics) return [{ json: { status: 'error', cmd: 'status', message: 'No data. Run seed first.' } }];
  const artLookup = buildArtLookup(epics);
  const plan = readKV('pql:plans:weeks:' + weekId);
  const rygInput = body.ryg || {};
  const activeEpics = [];
  for (const e of epics.epics) { if (state.epics_status[e.epic_id] === 'active') { const total = e.artifacts.length; const shipped = e.artifacts.filter(a => (state.artifacts_status[a.artifact_id] || {}).status === 'shipped').length; activeEpics.push({ epic_id: e.epic_id, title: e.title, progress: shipped + '/' + total }); } }
  const sevenAgo = new Date(now); sevenAgo.setDate(sevenAgo.getDate() - 7); const sevenAgoStr = sevenAgo.toISOString().slice(0,10);
  const lastWeekShips = state.xp_ledger.filter(e => e.date >= sevenAgoStr);
  const lastWeekXP = lastWeekShips.reduce((s,e) => s + e.xp, 0);
  const committedRYG = (plan ? plan.committed_artifacts : []).map(aid => { const info = artLookup[aid] || {}; const st = state.artifacts_status[aid] || {}; const ryg = rygInput[aid] || (st.dependency && st.dependency.exists ? 'yellow' : 'green'); const mit = st.dependency && st.dependency.exists ? 'Waiting: ' + st.dependency.waiting_on + '. Ping: ' + st.dependency.ping_date : 'On track'; return { artifact_id: aid, title: info.title || aid, epic_title: info.epic_title || '', type: info.type || '?', xp: info.xp || 0, ryg, mitigation: mit }; });
  const allDeps = [];
  for (const aid of Object.keys(state.artifacts_status)) { const a = state.artifacts_status[aid]; if (a.status !== 'shipped' && a.dependency && a.dependency.exists) { const info = artLookup[aid] || {}; allDeps.push({ artifact_id: aid, title: info.title || aid, waiting_on: a.dependency.waiting_on, ping_date: a.dependency.ping_date, notes: a.dependency.notes }); } }
  const parkedList = (plan ? plan.parked_artifacts : []).map(aid => { const info = artLookup[aid] || {}; const st = state.artifacts_status[aid] || {}; return { artifact_id: aid, title: info.title || aid, epic_title: info.epic_title || '', parked_waiting_on: st.parked_waiting_on || '' }; });
  const decisions = body.decisions || [];
  const pace = computePace(state);
  const opsOpen = (state.ops_log || []).filter(o => o.status === 'open');
  const opsDoneWeek = (state.ops_log || []).filter(o => o.status === 'done' && o.completed_at && o.completed_at >= sevenAgoStr);
  const mastOpen = (state.mastery_log || []).filter(m => m.status === 'open');
  const mastDoneWeek = (state.mastery_log || []).filter(m => m.status === 'done' && m.completed_at && m.completed_at >= sevenAgoStr);
  const leverageThisWeek = { decide: 0, absorb: 0, align: 0, clear: 0 };
  for (const e of state.xp_ledger) { const wk = getWeekId(new Date(e.date)); if (wk === weekId && e.leverage_type) { leverageThisWeek[e.leverage_type] = (leverageThisWeek[e.leverage_type] || 0) + 1; } }
  const report = { title: 'Weekly Portfolio Pulse', date: dateStr, week_id: weekId, pace, active_epics: activeEpics, shipped_last_week: lastWeekShips.map(e => ({ artifact_id: e.artifact_id, title: (artLookup[e.artifact_id] || {}).title || e.artifact_id, epic_id: e.epic_id, xp: e.xp })), xp_earned_last_week: lastWeekXP, xp_breakdown: lastWeekShips, committed_artifacts_ryg: committedRYG, stretch_artifacts: (plan ? plan.stretch_artifacts : []).map(aid => ({ artifact_id: aid, title: (artLookup[aid] || {}).title || aid })), risks_count: committedRYG.filter(c => c.ryg !== 'green').length, decisions_needed: decisions, dependencies: allDeps, parked: parkedList, quests: plan ? plan.quests : [], moves: plan ? plan.moves : [], leverage_this_week: leverageThisWeek, ops_summary: { open: opsOpen, open_count: opsOpen.length, done_this_week: opsDoneWeek, done_this_week_count: opsDoneWeek.length }, mastery_summary: { open: mastOpen, open_count: mastOpen.length, done_this_week: mastDoneWeek, done_this_week_count: mastDoneWeek.length } };
  writeKV('pql:outputs:status_email:' + dateStr, report);
  return [{ json: { status: 'ok', cmd: 'status', ...report, output_key: 'pql:outputs:status_email:' + dateStr } }];
}

// ══════════════════════════════════════════════════════
// /wrapup
// ══════════════════════════════════════════════════════
function handleWrapup() {
  const state = readKV('pql:state:state_json');
  const epics = readKV('pql:library:epics_json');
  if (!state || !epics) return [{ json: { status: 'error', cmd: 'wrapup', message: 'No state. Run /init first. Storage: ' + PQL_DIR, storage_path: PQL_DIR, existing_keys: listKVKeys() } }];
  const artLookup = buildArtLookup(epics);
  const activeArts = [];
  for (const aid of Object.keys(state.artifacts_status)) { const a = state.artifacts_status[aid]; if (a.status !== 'shipped') { const info = artLookup[aid] || {}; activeArts.push({ artifact_id: aid, title: info.title || aid, type: info.type || '?', xp: info.xp || 0, status: a.status, epic_id: a.epic_id, epic_title: info.epic_title || a.epic_id, has_dependency: a.dependency && a.dependency.exists }); } }
  const shipped = body.shipped || [];
  const leverageTypes = body.leverage_types || {};
  if (shipped.length === 0) { return [{ json: { status: 'ok', cmd: 'wrapup', mode: 'select', message: 'Send again with shipped array.', active_artifacts: activeArts, active_count: activeArts.length } }]; }
  const results = []; let xpEarned = 0; const ledgerNew = [];
  const shippedEpicIds = [];
  for (const aid of shipped) { const a = state.artifacts_status[aid]; if (!a) { results.push({ artifact_id: aid, action: 'skipped', reason: 'not found' }); continue; } if (a.status === 'shipped') { results.push({ artifact_id: aid, action: 'skipped', reason: 'already shipped' }); continue; } const info = artLookup[aid] || {}; a.status = 'shipped'; a.last_touched = dateStr; a.shipped_dates.push(dateStr); const xp = info.xp || 0; xpEarned += xp; const levType = leverageTypes[aid] || null; if (levType) { if (!a.leverage_type) a.leverage_type = levType; } const entry = { date: dateStr, artifact_id: aid, epic_id: a.epic_id, xp, note: 'Shipped: ' + (info.title || aid), leverage_type: levType }; state.xp_ledger.push(entry); ledgerNew.push(entry); results.push({ artifact_id: aid, title: info.title || aid, type: info.type || '?', xp, action: 'shipped', leverage_type: levType }); shippedEpicIds.push(a.epic_id); }
  const epicBonuses = checkAllEpicCompletions(state, epics, shippedEpicIds, dateStr);
  for (const b of epicBonuses) { xpEarned += b.xp; ledgerNew.push(b.entry); results.push({ artifact_id: b.bonusArtId, title: b.epic_title + ' — Epic Complete!', type: 'bonus', xp: b.xp, action: 'epic_bonus' }); }
  if (epicBonuses.length > 0) writeKV('pql:library:epics_json', epics);
  state.current_date = dateStr;
  const remaining = []; const openDeps = [];
  for (const aid of Object.keys(state.artifacts_status)) { const a = state.artifacts_status[aid]; const info = artLookup[aid] || {}; if (a.status !== 'shipped') remaining.push({ artifact_id: aid, title: info.title || aid, status: a.status, epic_id: a.epic_id }); if (a.status !== 'shipped' && a.dependency && a.dependency.exists) openDeps.push({ artifact_id: aid, waiting_on: a.dependency.waiting_on, ping_date: a.dependency.ping_date }); }
  writeKV('pql:state:state_json', state);
  const dailyLog = { date: dateStr, week_id: weekId, shipped: results.filter(r => r.action === 'shipped'), xp_earned: xpEarned, ops_notes: body.ops_notes || '', mastery_notes: body.mastery_notes || '', notes: body.notes || free_text || '', remaining_open: remaining, open_dependencies: openDeps, created_at: isoNow };
  writeKV('pql:logs:daily:' + dateStr, dailyLog);
  const totalXP = state.xp_ledger.reduce((s,e) => s + e.xp, 0);
  const pace = computePace(state);
  // Compute leverage counts for this week
  const leverageCounts = { decide: 0, absorb: 0, align: 0, clear: 0 };
  const leverageDetails = [];
  for (const e of state.xp_ledger) { const wk = getWeekId(new Date(e.date)); if (wk === weekId && e.leverage_type) { leverageCounts[e.leverage_type] = (leverageCounts[e.leverage_type] || 0) + 1; } }
  for (const r of results) { if (r.action === 'shipped' && r.leverage_type) { leverageDetails.push({ artifact_id: r.artifact_id, title: r.title, leverage_type: r.leverage_type }); } }
  const leverageSummary = { decide: 0, absorb: 0, align: 0, clear: 0 };
  for (const r of results) { if (r.action === 'shipped' && r.leverage_type) { leverageSummary[r.leverage_type] = (leverageSummary[r.leverage_type] || 0) + 1; } }
  return [{ json: { status: 'ok', cmd: 'wrapup', mode: 'completed', date: dateStr, week_id: weekId, ships: results, xp_earned_today: xpEarned, xp_total: totalXP, xp_breakdown: ledgerNew, epic_bonuses: epicBonuses.map(b => ({ epic_id: b.entry.epic_id, epic_title: b.epic_title, bonus_xp: b.xp })), ops_notes: body.ops_notes || '(none)', mastery_notes: body.mastery_notes || '(none)', notes: body.notes || free_text || '(none)', remaining_open: remaining, remaining_count: remaining.length, open_dependencies: openDeps, daily_log_key: 'pql:logs:daily:' + dateStr, pace, leverage_summary: leverageSummary, leverage_details: leverageDetails, leverage_this_week: leverageCounts } }];
}

// ══════════════════════════════════════════════════════
// /ops — View, add, complete, and ping admin/ops tasks
// ══════════════════════════════════════════════════════
function handleOps() {
  const state = readKV('pql:state:state_json');
  if (!state) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'No data. Run /init first.' } }];

  if (!state.ops_log) state.ops_log = [];
  if (!state.mastery_log) state.mastery_log = [];

  const opsTexts = new Set(state.ops_log.map(o => o.text));
  const mastTexts = new Set(state.mastery_log.map(m => m.text));
  for (const item of (state.inbox_items || [])) {
    if (item.suggested_lane === 'ops_admin' && !opsTexts.has(item.text)) {
      state.ops_log.push({ id: 'OPS-' + String(state.ops_log.length + 1).padStart(3,'0'), text: item.text, status: 'open', added_at: item.captured_at || isoNow, completed_at: null, waiting_on: '', ping_date: '', notes: '' });
      opsTexts.add(item.text);
    }
    if (item.suggested_lane === 'mastery' && !mastTexts.has(item.text)) {
      state.mastery_log.push({ id: 'MST-' + String(state.mastery_log.length + 1).padStart(3,'0'), text: item.text, status: 'open', added_at: item.captured_at || isoNow, completed_at: null, notes: '' });
      mastTexts.add(item.text);
    }
  }
  // Backfill missing ids on ops items
  { const usedIds = new Set(state.ops_log.filter(o => o.id).map(o => o.id));
    let counter = state.ops_log.length;
    for (const o of state.ops_log) {
      if (!o.id) {
        let newId;
        do { counter++; newId = 'OPS-' + String(counter).padStart(3,'0'); } while (usedIds.has(newId));
        o.id = newId; usedIds.add(newId);
      }
      if (o.waiting_on === undefined) o.waiting_on = '';
      if (o.ping_date === undefined) o.ping_date = '';
    }
  }
  // Backfill missing ids on mastery items
  { const usedMIds = new Set(state.mastery_log.filter(m => m.id).map(m => m.id));
    let mCounter = state.mastery_log.length;
    for (const m of state.mastery_log) {
      if (!m.id) {
        let newId;
        do { mCounter++; newId = 'MST-' + String(mCounter).padStart(3,'0'); } while (usedMIds.has(newId));
        m.id = newId; usedMIds.add(newId);
      }
    }
  }

  const subCmd = body.sub_action || body.action || 'view';

  if (subCmd === 'pings') {
    const epics = readKV('pql:library:epics_json');
    const artLookup = buildArtLookup(epics);
    const overdue = state.ops_log.filter(o => o.status === 'open' && o.ping_date && o.ping_date <= dateStr);
    const artDeps = [];
    for (const aid of Object.keys(state.artifacts_status || {})) {
      const a = state.artifacts_status[aid];
      if (a.status !== 'shipped' && a.dependency && a.dependency.exists && a.dependency.ping_date && a.dependency.ping_date <= dateStr) {
        const info = artLookup[aid] || {};
        artDeps.push({ artifact_id: aid, title: info.title || aid, waiting_on: a.dependency.waiting_on, ping_date: a.dependency.ping_date });
      }
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'pings', date: dateStr, ops_overdue: overdue, ops_overdue_count: overdue.length, artifact_overdue: artDeps, artifact_overdue_count: artDeps.length, total_overdue: overdue.length + artDeps.length } }];
  }

  if (subCmd === 'add') {
    const text = body.text || free_text;
    if (!text || !text.trim()) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide text to add.' } }];
    const newId = 'OPS-' + String(state.ops_log.length + 1).padStart(3,'0');
    const newItem = { id: newId, text: text.trim(), status: 'open', added_at: isoNow, completed_at: null, waiting_on: body.waiting_on || '', ping_date: body.ping_date || '', notes: body.notes || '' };
    state.ops_log.push(newItem);
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'added', item: newItem, open_count: state.ops_log.filter(o => o.status === 'open').length, total_count: state.ops_log.length } }];
  }

  if (subCmd === 'set_ping') {
    const id = body.id;
    if (!id) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide id of ops item.' } }];
    const item = state.ops_log.find(o => o.id === id);
    if (!item) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Ops item not found: ' + id } }];
    if (body.waiting_on !== undefined) item.waiting_on = body.waiting_on;
    if (body.ping_date !== undefined) item.ping_date = body.ping_date;
    if (body.notes !== undefined) item.notes = body.notes;
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'ping_set', item, message: 'Ping set: ' + item.id + ' \u2192 ' + (item.waiting_on || '?') + ' by ' + (item.ping_date || '?') } }];
  }

  if (subCmd === 'done' || subCmd === 'complete') {
    const ids = body.ids || body.completed || [];
    if (ids.length === 0) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide ids array of ops items to mark done.' } }];
    const results = [];
    for (const id of ids) {
      const item = state.ops_log.find(o => o.id === id);
      if (item && item.status !== 'done') {
        item.status = 'done'; item.completed_at = dateStr;
        if (body.notes) item.notes = body.notes;
        results.push({ id: item.id, text: item.text, action: 'completed' });
      } else if (item) { results.push({ id, action: 'already_done' }); }
      else { results.push({ id, action: 'not_found' }); }
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'completed', results, open_count: state.ops_log.filter(o => o.status === 'open').length, total_count: state.ops_log.length } }];
  }

  if (subCmd === 'add_mastery') {
    const text = body.text || free_text;
    if (!text || !text.trim()) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide text to add.' } }];
    const newId = 'MST-' + String(state.mastery_log.length + 1).padStart(3,'0');
    const newItem = { id: newId, text: text.trim(), status: 'open', added_at: isoNow, completed_at: null, notes: body.notes || '' };
    state.mastery_log.push(newItem);
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'mastery_added', item: newItem, open_count: state.mastery_log.filter(m => m.status === 'open').length } }];
  }

  if (subCmd === 'done_mastery') {
    const ids = body.ids || [];
    const results = [];
    for (const id of ids) {
      const item = state.mastery_log.find(m => m.id === id);
      if (item && item.status !== 'done') {
        item.status = 'done'; item.completed_at = dateStr;
        results.push({ id: item.id, text: item.text, action: 'completed' });
      }
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'mastery_completed', results, open_count: state.mastery_log.filter(m => m.status === 'open').length } }];
  }

  if (subCmd === 'delete' || subCmd === 'remove') {
    const id = body.id;
    if (!id) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide id of ops item to delete.' } }];
    const idx = state.ops_log.findIndex(o => o.id === id);
    if (idx < 0) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Ops item not found: ' + id } }];
    const removed = state.ops_log.splice(idx, 1)[0];
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'deleted', item: removed, open_count: state.ops_log.filter(o => o.status === 'open').length, message: 'Ops task deleted: ' + removed.text } }];
  }

  if (subCmd === 'reorder') {
    const ids = body.ids;
    if (!ids || !Array.isArray(ids)) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide ids array in desired order.' } }];
    const opsMap = {};
    for (const o of state.ops_log) opsMap[o.id] = o;
    const reordered = [];
    for (const id of ids) { if (opsMap[id]) { reordered.push(opsMap[id]); delete opsMap[id]; } }
    for (const o of Object.values(opsMap)) reordered.push(o);
    state.ops_log = reordered;
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'reordered', count: reordered.length, message: 'Ops tasks reordered.' } }];
  }

  if (subCmd === 'delete_mastery' || subCmd === 'remove_mastery') {
    const id = body.id;
    if (!id) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide id of mastery item to delete.' } }];
    const idx = state.mastery_log.findIndex(m => m.id === id);
    if (idx < 0) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Mastery item not found: ' + id } }];
    const removed = state.mastery_log.splice(idx, 1)[0];
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'mastery_deleted', item: removed, open_count: state.mastery_log.filter(m => m.status === 'open').length, message: 'Mastery task deleted: ' + removed.text } }];
  }

  if (subCmd === 'reorder_mastery') {
    const ids = body.ids;
    if (!ids || !Array.isArray(ids)) return [{ json: { _route: 'direct', status: 'error', cmd: 'ops', message: 'Provide ids array in desired order.' } }];
    const mastMap = {};
    for (const m of state.mastery_log) mastMap[m.id] = m;
    const reordered = [];
    for (const id of ids) { if (mastMap[id]) { reordered.push(mastMap[id]); delete mastMap[id]; } }
    for (const m of Object.values(mastMap)) reordered.push(m);
    state.mastery_log = reordered;
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'ops', mode: 'mastery_reordered', count: reordered.length, message: 'Mastery tasks reordered.' } }];
  }

  writeKV('pql:state:state_json', state);

  const openOps = state.ops_log.filter(o => o.status === 'open');
  const overdueOps = openOps.filter(o => o.ping_date && o.ping_date <= dateStr);
  const waitingOps = openOps.filter(o => o.ping_date && o.ping_date > dateStr);
  const plainOps = openOps.filter(o => !o.ping_date);
  const doneOps = state.ops_log.filter(o => o.status === 'done');
  const sevenAgo = new Date(now); sevenAgo.setDate(sevenAgo.getDate() - 7); const sevenAgoStr2 = sevenAgo.toISOString().slice(0,10);
  const recentDoneOps = doneOps.filter(o => o.completed_at && o.completed_at >= sevenAgoStr2);
  const openMastery = state.mastery_log.filter(m => m.status === 'open');
  const doneMastery = state.mastery_log.filter(m => m.status === 'done');
  const recentDoneMastery = doneMastery.filter(m => m.completed_at && m.completed_at >= sevenAgoStr2);

  return [{ json: {
    _route: 'direct', status: 'ok', cmd: 'ops', mode: 'view', date: dateStr,
    ops: {
      overdue: overdueOps, overdue_count: overdueOps.length,
      waiting: waitingOps, waiting_count: waitingOps.length,
      open_no_ping: plainOps, open_no_ping_count: plainOps.length,
      open: openOps, open_count: openOps.length,
      done_this_week: recentDoneOps, done_this_week_count: recentDoneOps.length,
      total_done: doneOps.length, total: state.ops_log.length
    },
    mastery: {
      open: openMastery, open_count: openMastery.length,
      done_this_week: recentDoneMastery, done_this_week_count: recentDoneMastery.length,
      total_done: doneMastery.length, total: state.mastery_log.length
    },
    message: overdueOps.length > 0
      ? overdueOps.length + ' OVERDUE ping(s)! ' + openOps.length + ' open ops, ' + openMastery.length + ' open mastery.'
      : openOps.length + ' open ops tasks, ' + openMastery.length + ' open mastery tasks.'
  } }];
}

// /edit — Rename epics (and artifacts)
// ══════════════════════════════════════════════════════
function handleEdit() {
  const state = readKV('pql:state:state_json');
  const epics = readKV('pql:library:epics_json');
  if (!state || !epics) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'No data. Run /init first.' } }];

  const action = body.sub_action || body.action || '';

  // ── BACKFILL SHIPPED DATES ──
  if (action === 'backfill_shipped') {
    const entries = body.entries || [];
    if (entries.length === 0) {
      // Return all artifacts grouped by epic for interactive selection
      const epicList = epics.epics.map(e => {
        const epicStatus = state.epics_status[e.epic_id] || 'active';
        return {
          epic_id: e.epic_id,
          title: e.title,
          status: epicStatus,
          artifacts: e.artifacts.map(a => {
            const aState = state.artifacts_status[a.artifact_id] || {};
            const shippedDates = aState.shipped_dates || [];
            return {
              artifact_id: a.artifact_id,
              title: a.title,
              type: a.type,
              xp: a.xp,
              status: aState.status || 'open',
              shipped_date: shippedDates.length > 0 ? shippedDates[shippedDates.length - 1] : null
            };
          })
        };
      });
      return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'backfill_select', epics: epicList } }];
    }
    // Apply backfill entries
    const results = [];
    for (const entry of entries) {
      const aid = entry.artifact_id;
      const shipDate = entry.shipped_date;
      if (!aid || !shipDate) { results.push({ artifact_id: aid || '?', status: 'skipped', reason: 'missing artifact_id or shipped_date' }); continue; }
      const a = state.artifacts_status[aid];
      if (!a) { results.push({ artifact_id: aid, status: 'skipped', reason: 'not found in state' }); continue; }
      if (!a.shipped_dates) a.shipped_dates = [];
      if (!a.shipped_dates.includes(shipDate)) a.shipped_dates.push(shipDate);
      a.shipped_dates.sort();
      if (a.status !== 'shipped') { a.status = 'shipped'; a.last_touched = shipDate; }
      const info = buildArtLookup(epics)[aid] || {};
      const xp = info.xp || 0;
      // Write xp_ledger entry so streak tracker picks up the backfilled date
      if (!state.xp_ledger) state.xp_ledger = [];
      const alreadyInLedger = state.xp_ledger.some(e => e.artifact_id === aid && e.date === shipDate);
      if (!alreadyInLedger) {
        state.xp_ledger.push({ date: shipDate, artifact_id: aid, epic_id: a.epic_id, xp, note: 'Backfill: ' + (info.title || aid) });
      }
      results.push({ artifact_id: aid, title: info.title || aid, status: 'ok', shipped_date: shipDate, xp });
    }
    // Check for epic completions
    const shippedEpicIds = results.filter(r => r.status === 'ok').map(r => (state.artifacts_status[r.artifact_id] || {}).epic_id).filter(Boolean);
    const epicBonuses = checkAllEpicCompletions(state, epics, shippedEpicIds, dateStr);
    if (epicBonuses.length > 0) writeKV('pql:library:epics_json', epics);
    let totalXP = results.filter(r => r.status === 'ok').reduce((s, r) => s + (r.xp || 0), 0);
    for (const b of epicBonuses) { totalXP += b.xp; }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'backfill_applied', applied: results.filter(r => r.status === 'ok').length, skipped: results.filter(r => r.status === 'skipped').length, xp_earned: totalXP, epic_bonuses: epicBonuses, results, pace: computePace(state) } }];
  }

  if (action === 'delete_artifact') {
    const aid = body.artifact_id;
    if (!aid) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide artifact_id to delete.' } }];
    const artState = state.artifacts_status[aid];
    if (artState && artState.status === 'shipped') return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Cannot delete shipped artifact: ' + aid } }];
    let found = false; let epicId = ''; let title = '';
    for (const e of epics.epics) {
      const idx = e.artifacts.findIndex(a => a.artifact_id === aid);
      if (idx >= 0) {
        title = e.artifacts[idx].title;
        epicId = e.epic_id;
        e.artifacts.splice(idx, 1);
        for (const ms of (e.milestones || [])) {
          ms.artifacts = (ms.artifacts || []).filter(a => a !== aid);
        }
        found = true;
        break;
      }
    }
    if (!found) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Artifact not found: ' + aid } }];
    delete state.artifacts_status[aid];
    if (state.weekly) {
      state.weekly.committed_artifacts = (state.weekly.committed_artifacts || []).filter(a => a !== aid);
      state.weekly.stretch_artifacts = (state.weekly.stretch_artifacts || []).filter(a => a !== aid);
      state.weekly.parked_artifacts = (state.weekly.parked_artifacts || []).filter(a => a !== aid);
      state.weekly.pings_due = (state.weekly.pings_due || []).filter(p => p.artifact_id !== aid);
      for (const q of (state.weekly.quests || [])) {
        if (q.friday_finishline_artifact_id === aid) q.friday_finishline_artifact_id = '';
      }
      for (const m of (state.weekly.moves || [])) {
        m.linked_artifact_ids = (m.linked_artifact_ids || []).filter(a => a !== aid);
      }
    }
    writeKV('pql:library:epics_json', epics);
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'deleted_artifact', artifact_id: aid, epic_id: epicId, title, message: 'Artifact deleted: ' + title } }];
  }


  // ── DELETE EPIC ──
  if (action === 'delete_epic') {
    const eid = body.epic_id;
    if (!eid) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide epic_id to delete.' } }];
    const epicIdx = epics.epics.findIndex(e => e.epic_id === eid);
    if (epicIdx < 0) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Epic not found: ' + eid } }];
    const epic = epics.epics[epicIdx];
    const hasShipped = epic.artifacts.some(a => {
      const st = (state.artifacts_status[a.artifact_id] || {}).status;
      return st === 'shipped';
    });
    if (hasShipped) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Cannot delete epic with shipped artifacts: ' + eid + '. Remove shipped artifacts first or archive instead.' } }];
    // Remove all artifacts from state
    for (const a of epic.artifacts) {
      delete state.artifacts_status[a.artifact_id];
      if (state.weekly) {
        state.weekly.committed_artifacts = (state.weekly.committed_artifacts || []).filter(x => x !== a.artifact_id);
        state.weekly.stretch_artifacts = (state.weekly.stretch_artifacts || []).filter(x => x !== a.artifact_id);
        state.weekly.parked_artifacts = (state.weekly.parked_artifacts || []).filter(x => x !== a.artifact_id);
        state.weekly.pings_due = (state.weekly.pings_due || []).filter(p => p.artifact_id !== a.artifact_id);
        for (const q of (state.weekly.quests || [])) {
          if (q.friday_finishline_artifact_id === a.artifact_id) q.friday_finishline_artifact_id = '';
          if (q.epic_id === eid) q.epic_id = '';
        }
        for (const m of (state.weekly.moves || [])) {
          m.linked_artifact_ids = (m.linked_artifact_ids || []).filter(x => x !== a.artifact_id);
        }
      }
    }
    delete state.epics_status[eid];
    const title = epic.title;
    const artCount = epic.artifacts.length;
    epics.epics.splice(epicIdx, 1);
    writeKV('pql:library:epics_json', epics);
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'deleted_epic', epic_id: eid, title, artifacts_removed: artCount, message: 'Epic deleted: ' + title + ' (' + artCount + ' artifacts removed)' } }];
  }

  // ── RESIZE ARTIFACT (change type/XP) ──
  if (action === 'resize_artifact') {
    const aid = body.artifact_id;
    const newType = body.new_type;
    if (!aid || !newType) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide artifact_id and new_type (slice|small|medium|large).' } }];
    const validTypes = ['slice', 'small', 'medium', 'large'];
    if (!validTypes.includes(newType)) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Invalid type: ' + newType + '. Use: ' + validTypes.join(', ') } }];
    const xpMap = { slice: 2, small: 3, medium: 8, large: 12 };
    const newXP = xpMap[newType];
    let found = false; let epicId = ''; let oldType = ''; let oldXP = 0; let title = '';
    for (const e of epics.epics) {
      const art = e.artifacts.find(a => a.artifact_id === aid);
      if (art) {
        oldType = art.type;
        oldXP = art.xp;
        title = art.title;
        epicId = e.epic_id;
        art.type = newType;
        art.xp = newXP;
        found = true;
        break;
      }
    }
    if (!found) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Artifact not found: ' + aid } }];
    writeKV('pql:library:epics_json', epics);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'resized_artifact', artifact_id: aid, epic_id: epicId, title, old_type: oldType, old_xp: oldXP, new_type: newType, new_xp: newXP, message: 'Resized: ' + title + ' (' + oldType + ' ' + oldXP + 'XP -> ' + newType + ' ' + newXP + 'XP)' } }];
  }

  // ── PARK ARTIFACT ──
  if (action === 'park_artifact') {
    const aid = body.artifact_id;
    if (!aid) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide artifact_id to park.' } }];
    const artState = state.artifacts_status[aid];
    if (!artState) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Artifact not found in state: ' + aid } }];
    if (artState.status === 'shipped') return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Cannot park a shipped artifact: ' + aid } }];
    const oldStatus = artState.status;
    artState.status = 'parked';
    artState.last_touched = dateStr;
    // Store optional waiting_on reason (what external dependency blocks this artifact)
    const waitingOn = (body.waiting_on || '').trim();
    artState.parked_waiting_on = waitingOn;
    let title = aid; let epicId = '';
    for (const e of epics.epics) {
      const art = e.artifacts.find(a => a.artifact_id === aid);
      if (art) { title = art.title; epicId = e.epic_id; break; }
    }
    // Also move to parked in weekly plan if exists
    if (state.weekly) {
      state.weekly.committed_artifacts = (state.weekly.committed_artifacts || []).filter(a => a !== aid);
      state.weekly.stretch_artifacts = (state.weekly.stretch_artifacts || []).filter(a => a !== aid);
      if (!(state.weekly.parked_artifacts || []).includes(aid)) {
        if (!state.weekly.parked_artifacts) state.weekly.parked_artifacts = [];
        state.weekly.parked_artifacts.push(aid);
      }
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'parked_artifact', artifact_id: aid, epic_id: epicId, title, old_status: oldStatus, waiting_on: waitingOn, message: 'Parked: ' + title + (waitingOn ? ' (waiting on: ' + waitingOn + ')' : ' (was ' + oldStatus + ')') } }];
  }

  // ── UNPARK ARTIFACT ──
  if (action === 'unpark_artifact') {
    const aid = body.artifact_id;
    if (!aid) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide artifact_id to unpark.' } }];
    const artState = state.artifacts_status[aid];
    if (!artState) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Artifact not found in state: ' + aid } }];
    if (artState.status !== 'parked') return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Artifact is not parked: ' + aid + ' (status: ' + artState.status + ')' } }];
    artState.status = 'open';
    artState.last_touched = dateStr;
    artState.parked_waiting_on = '';
    let title = aid; let epicId = '';
    for (const e of epics.epics) {
      const art = e.artifacts.find(a => a.artifact_id === aid);
      if (art) { title = art.title; epicId = e.epic_id; break; }
    }
    if (state.weekly) {
      state.weekly.parked_artifacts = (state.weekly.parked_artifacts || []).filter(a => a !== aid);
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'unparked_artifact', artifact_id: aid, epic_id: epicId, title, message: 'Unparked: ' + title + ' (now open)' } }];
  }

  // ── RESOLVE WAITING: check off a waiting_on item → auto-unpark all matching artifacts ──
  if (action === 'resolve_waiting') {
    const waitingOn = (body.waiting_on || '').trim();
    if (!waitingOn) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide waiting_on text to resolve.' } }];
    const artLookup = buildArtLookup(epics);
    const unparked = [];
    for (const aid of Object.keys(state.artifacts_status)) {
      const a = state.artifacts_status[aid];
      if (a.status === 'parked' && a.parked_waiting_on && a.parked_waiting_on.toLowerCase() === waitingOn.toLowerCase()) {
        a.status = 'open';
        a.last_touched = dateStr;
        a.parked_waiting_on = '';
        const info = artLookup[aid] || {};
        unparked.push({ artifact_id: aid, title: info.title || aid, epic_id: a.epic_id });
        // Remove from weekly parked list
        if (state.weekly) {
          state.weekly.parked_artifacts = (state.weekly.parked_artifacts || []).filter(x => x !== aid);
        }
      }
    }
    if (unparked.length === 0) return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'resolve_waiting', waiting_on: waitingOn, unparked: [], message: 'No parked artifacts found waiting on: ' + waitingOn } }];
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'resolve_waiting', waiting_on: waitingOn, unparked, message: 'Resolved "' + waitingOn + '" — unparked ' + unparked.length + ' artifact(s): ' + unparked.map(u => u.title).join(', ') } }];
  }


  // ── PARK EPIC ──
  if (action === 'park_epic') {
    const eid = body.epic_id;
    if (!eid) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide epic_id to park.' } }];
    const epicObj = epics.epics.find(e => e.epic_id === eid);
    if (!epicObj) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Epic not found: ' + eid } }];
    const currentStatus = state.epics_status[eid] || 'active';
    if (currentStatus === 'completed') return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Cannot park a completed epic: ' + eid } }];
    if (currentStatus === 'parked') return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Epic is already parked: ' + eid } }];
    state.epics_status[eid] = 'parked';
    const parkedArts = [];
    for (const a of epicObj.artifacts) {
      const aState = state.artifacts_status[a.artifact_id];
      if (aState && aState.status !== 'shipped' && aState.status !== 'parked') {
        aState.status = 'parked';
        aState.last_touched = dateStr;
        parkedArts.push({ artifact_id: a.artifact_id, title: a.title });
        if (state.weekly) {
          state.weekly.committed_artifacts = (state.weekly.committed_artifacts || []).filter(x => x !== a.artifact_id);
          state.weekly.stretch_artifacts = (state.weekly.stretch_artifacts || []).filter(x => x !== a.artifact_id);
          if (!(state.weekly.parked_artifacts || []).includes(a.artifact_id)) {
            if (!state.weekly.parked_artifacts) state.weekly.parked_artifacts = [];
            state.weekly.parked_artifacts.push(a.artifact_id);
          }
        }
      }
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'parked_epic', epic_id: eid, title: epicObj.title, old_status: currentStatus, artifacts_parked: parkedArts.length, parked_artifacts: parkedArts, message: 'Parked epic: ' + epicObj.title + ' (' + parkedArts.length + ' artifacts parked)' } }];
  }

  // ── UNPARK EPIC ──
  if (action === 'unpark_epic') {
    const eid = body.epic_id;
    if (!eid) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide epic_id to unpark.' } }];
    const epicObj = epics.epics.find(e => e.epic_id === eid);
    if (!epicObj) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Epic not found: ' + eid } }];
    const currentStatus = state.epics_status[eid] || 'active';
    if (currentStatus !== 'parked') return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Epic is not parked: ' + eid + ' (status: ' + currentStatus + ')' } }];
    state.epics_status[eid] = 'active';
    const unparkedArts = [];
    for (const a of epicObj.artifacts) {
      const aState = state.artifacts_status[a.artifact_id];
      if (aState && aState.status === 'parked') {
        aState.status = 'open';
        aState.last_touched = dateStr;
        aState.parked_waiting_on = '';
        unparkedArts.push({ artifact_id: a.artifact_id, title: a.title });
        if (state.weekly) {
          state.weekly.parked_artifacts = (state.weekly.parked_artifacts || []).filter(x => x !== a.artifact_id);
        }
      }
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'unparked_epic', epic_id: eid, title: epicObj.title, artifacts_unparked: unparkedArts.length, unparked_artifacts: unparkedArts, message: 'Unparked epic: ' + epicObj.title + ' (' + unparkedArts.length + ' artifacts reactivated)' } }];
  }

  // ── REORDER ALL (atomic: epics + all artifact orders in one write) ──
  if (action === 'reorder_all') {
    const epicOrder = body.epic_order;
    const artOrders = body.artifact_orders || {};
    let epicReordered = false;
    let artsReordered = 0;

    if (epicOrder && Array.isArray(epicOrder) && epicOrder.length > 0) {
      const epicMap = {};
      for (const e of epics.epics) epicMap[e.epic_id] = e;
      const reordered = [];
      for (const eid of epicOrder) {
        if (epicMap[eid]) { reordered.push(epicMap[eid]); delete epicMap[eid]; }
      }
      for (const e of Object.values(epicMap)) reordered.push(e);
      epics.epics = reordered;
      epicReordered = true;
    }

    for (const [eid, order] of Object.entries(artOrders)) {
      if (!Array.isArray(order) || order.length === 0) continue;
      const epic = epics.epics.find(e => e.epic_id === eid);
      if (!epic) continue;
      const artMap = {};
      for (const a of epic.artifacts) artMap[a.artifact_id] = a;
      const reordered = [];
      for (const aid of order) {
        if (artMap[aid]) { reordered.push(artMap[aid]); delete artMap[aid]; }
      }
      for (const a of Object.values(artMap)) reordered.push(a);
      epic.artifacts = reordered;
      artsReordered++;
    }

    writeKV('pql:library:epics_json', epics);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'reordered_all', epic_reordered: epicReordered, artifacts_reordered_epics: artsReordered, message: 'All orders saved (' + (epicReordered ? 'epics + ' : '') + artsReordered + ' artifact lists)' } }];
  }

  // ── REORDER ARTIFACTS within an epic ──
  if (action === 'reorder_artifacts') {
    const eid = body.epic_id;
    const order = body.artifact_order;
    if (!eid || !order || !Array.isArray(order)) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide epic_id and artifact_order array.' } }];
    const epic = epics.epics.find(e => e.epic_id === eid);
    if (!epic) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Epic not found: ' + eid } }];
    const artMap = {};
    for (const a of epic.artifacts) artMap[a.artifact_id] = a;
    const reordered = [];
    for (const aid of order) {
      if (artMap[aid]) { reordered.push(artMap[aid]); delete artMap[aid]; }
    }
    for (const a of Object.values(artMap)) reordered.push(a);
    epic.artifacts = reordered;
    writeKV('pql:library:epics_json', epics);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'reordered_artifacts', epic_id: eid, artifact_count: reordered.length, message: 'Artifacts reordered in ' + eid } }];
  }

  // ── REORDER EPICS ──
  if (action === 'reorder_epics') {
    const order = body.epic_order;
    if (!order || !Array.isArray(order)) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Provide epic_order array.' } }];
    const epicMap = {};
    for (const e of epics.epics) epicMap[e.epic_id] = e;
    const reordered = [];
    for (const eid of order) {
      if (epicMap[eid]) { reordered.push(epicMap[eid]); delete epicMap[eid]; }
    }
    for (const e of Object.values(epicMap)) reordered.push(e);
    epics.epics = reordered;
    writeKV('pql:library:epics_json', epics);
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'reordered_epics', epic_count: reordered.length, message: 'Epics reordered.' } }];
  }

  const epicId = body.epic_id;
  const newTitle = body.new_title;
  const artifactId = body.artifact_id;
  const newArtTitle = body.new_artifact_title;

  if (!epicId && !artifactId) {
    const artLookup = buildArtLookup(epics);
    const epicList = epics.epics.map(e => ({
      epic_id: e.epic_id,
      title: e.title,
      status: state.epics_status[e.epic_id] || 'inactive',
      artifacts: e.artifacts.map(a => {
        const aState = state.artifacts_status[a.artifact_id] || {};
        return {
          artifact_id: a.artifact_id,
          title: a.title,
          type: a.type,
          xp: a.xp,
          status: aState.status || 'unknown',
          parked_waiting_on: aState.parked_waiting_on || ''
        };
      })
    }));
    return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'select', message: 'Send with epic_id + new_title to rename an epic, or artifact_id + new_artifact_title to rename an artifact.', epics: epicList } }];
  }

  const changes = [];

  if (epicId && newTitle) {
    const epic = epics.epics.find(e => e.epic_id === epicId);
    if (!epic) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Epic not found: ' + epicId } }];
    const oldTitle = epic.title;
    epic.title = newTitle.trim();
    changes.push({ type: 'epic_renamed', epic_id: epicId, old_title: oldTitle, new_title: epic.title });
  }

  if (artifactId && newArtTitle) {
    let found = false;
    for (const e of epics.epics) {
      const art = e.artifacts.find(a => a.artifact_id === artifactId);
      if (art) {
        const oldTitle = art.title;
        art.title = newArtTitle.trim();
        changes.push({ type: 'artifact_renamed', artifact_id: artifactId, epic_id: e.epic_id, old_title: oldTitle, new_title: art.title });
        found = true;
        break;
      }
    }
    if (!found) return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'Artifact not found: ' + artifactId } }];
  }

  if (changes.length === 0) {
    return [{ json: { _route: 'direct', status: 'error', cmd: 'edit', message: 'No valid rename provided. Send epic_id+new_title or artifact_id+new_artifact_title. (received action=' + (body.action || 'none') + ', epic_id=' + (body.epic_id || 'none') + ', artifact_id=' + (body.artifact_id || 'none') + ')' } }];
  }

  writeKV('pql:library:epics_json', epics);
  return [{ json: { _route: 'direct', status: 'ok', cmd: 'edit', mode: 'applied', changes, message: changes.length + ' rename(s) applied.' } }];
}

// ══════════════════════════════════════════════════════
// /swap — Replace a Move mid-week (Rule 3: swap rule)
// ══════════════════════════════════════════════════════
function handleSwap() {
  const state = readKV('pql:state:state_json');
  const epics = readKV('pql:library:epics_json');
  if (!state || !epics) return [{ json: { _route: 'direct', status: 'error', cmd: 'swap', message: 'No data. Run /init first.' } }];
  const artLookup = buildArtLookup(epics);

  const plan = state.weekly;
  if (!plan || !plan.moves || plan.moves.length === 0) {
    return [{ json: { _route: 'direct', status: 'error', cmd: 'swap', message: 'No active weekly plan with moves. Run /start first.' } }];
  }

  const removeMoveId = body.remove_move_id;
  const newArtifactId = body.new_artifact_id;
  const newDescription = body.description;

  if (!removeMoveId || !newArtifactId) {
    const currentMoves = plan.moves.map(m => {
      const linkedInfo = (m.linked_artifact_ids || []).map(aid => {
        const info = artLookup[aid] || {};
        return { artifact_id: aid, title: info.title || aid, type: info.type || '?', xp: info.xp || 0 };
      });
      return { move_id: m.move_id, description: m.description, linked_artifacts: linkedInfo };
    });

    const moveArtIds = new Set();
    for (const m of plan.moves) { for (const aid of (m.linked_artifact_ids || [])) moveArtIds.add(aid); }

    const swappableArts = [];
    for (const e of epics.epics) {
      for (const a of e.artifacts) {
        const aState = state.artifacts_status[a.artifact_id];
        if (!aState) continue;
        if (aState.status === 'shipped' || moveArtIds.has(a.artifact_id)) continue;
        swappableArts.push({
          artifact_id: a.artifact_id,
          title: a.title,
          type: a.type,
          xp: a.xp,
          status: aState.status,
          epic_id: e.epic_id,
          epic_title: e.title
        });
      }
    }

    return [{ json: {
      _route: 'direct', status: 'ok', cmd: 'swap', mode: 'select',
      message: 'SWAP RULE: New work must replace a Move. Send remove_move_id + new_artifact_id.',
      current_moves: currentMoves,
      available_artifacts: swappableArts,
      available_count: swappableArts.length
    } }];
  }

  const moveIdx = plan.moves.findIndex(m => m.move_id === removeMoveId);
  if (moveIdx < 0) return [{ json: { _route: 'direct', status: 'error', cmd: 'swap', message: 'Move not found: ' + removeMoveId + '. Valid: ' + plan.moves.map(m => m.move_id).join(', ') } }];

  if (!state.artifacts_status[newArtifactId]) {
    return [{ json: { _route: 'direct', status: 'error', cmd: 'swap', message: 'Artifact not found: ' + newArtifactId } }];
  }

  const oldMove = JSON.parse(JSON.stringify(plan.moves[moveIdx]));
  const newInfo = artLookup[newArtifactId] || {};

  const parkedArts = [];
  for (const oldAid of (oldMove.linked_artifact_ids || [])) {
    if (state.artifacts_status[oldAid] && state.artifacts_status[oldAid].status !== 'shipped') {
      state.artifacts_status[oldAid].status = 'parked';
      state.artifacts_status[oldAid].last_touched = dateStr;
      parkedArts.push(oldAid);
      plan.committed_artifacts = (plan.committed_artifacts || []).filter(a => a !== oldAid);
      plan.stretch_artifacts = (plan.stretch_artifacts || []).filter(a => a !== oldAid);
      if (!(plan.parked_artifacts || []).includes(oldAid)) {
        if (!plan.parked_artifacts) plan.parked_artifacts = [];
        plan.parked_artifacts.push(oldAid);
      }
    }
  }

  state.artifacts_status[newArtifactId].status = 'committed';
  state.artifacts_status[newArtifactId].last_touched = dateStr;
  if (!(plan.committed_artifacts || []).includes(newArtifactId)) {
    plan.committed_artifacts.push(newArtifactId);
  }
  plan.parked_artifacts = (plan.parked_artifacts || []).filter(a => a !== newArtifactId);
  plan.stretch_artifacts = (plan.stretch_artifacts || []).filter(a => a !== newArtifactId);

  plan.moves[moveIdx] = {
    move_id: removeMoveId,
    description: newDescription || ('SWAPPED IN: ' + (newInfo.title || newArtifactId)),
    linked_artifact_ids: [newArtifactId],
    swapped_at: isoNow,
    replaced: { old_description: oldMove.description, old_artifact_ids: oldMove.linked_artifact_ids }
  };

  state.weekly = plan;
  writeKV('pql:plans:weeks:' + weekId, plan);
  writeKV('pql:state:state_json', state);

  return [{ json: {
    _route: 'direct', status: 'ok', cmd: 'swap', mode: 'completed',
    date: dateStr,
    old_move: { move_id: oldMove.move_id, description: oldMove.description, artifacts: (oldMove.linked_artifact_ids || []).map(aid => ({ artifact_id: aid, title: (artLookup[aid] || {}).title || aid })) },
    new_move: { move_id: removeMoveId, description: plan.moves[moveIdx].description, artifact_id: newArtifactId, title: newInfo.title || newArtifactId, xp: newInfo.xp || 0 },
    parked_artifacts: parkedArts.map(aid => ({ artifact_id: aid, title: (artLookup[aid] || {}).title || aid })),
    message: 'Move ' + removeMoveId + ' swapped. Old artifact(s) parked, ' + (newInfo.title || newArtifactId) + ' committed.'
  } }];
}

// ══════════════════════════════════════════════════════
// /files — Browse, read, edit, and write files on disk
// ══════════════════════════════════════════════════════
function handleFiles() {
  const action = body.sub_action || body.action || "list";
  const filePath = body.path || "";

  if (action === "list") {
    const tree = [];
    function walk(dir, rel) {
      if (!fs.existsSync(dir)) return;
      const entries = fs.readdirSync(dir, { withFileTypes: true }).sort((a, b) => {
        if (a.isDirectory() && !b.isDirectory()) return -1;
        if (!a.isDirectory() && b.isDirectory()) return 1;
        return a.name.localeCompare(b.name);
      });
      for (const e of entries) {
        const fullPath = pathMod.join(dir, e.name);
        const relPath = rel ? rel + "/" + e.name : e.name;
        if (e.isDirectory()) {
          tree.push({ type: "dir", name: e.name, path: relPath });
          walk(fullPath, relPath);
        } else {
          let size = 0; let mtime = "";
          try { const st = fs.statSync(fullPath); size = st.size; mtime = st.mtime.toISOString(); } catch {}
          tree.push({ type: "file", name: e.name, path: relPath, size, modified: mtime });
        }
      }
    }
    walk(PQL_DIR, "");
    return [{ json: { status: "ok", cmd: "files", mode: "list", storage_path: PQL_DIR, entries: tree, total: tree.length } }];
  }

  if (action === "read") {
    if (!filePath) return [{ json: { status: "error", cmd: "files", message: "Provide path to read." } }];
    const resolved = pathMod.resolve(PQL_DIR, filePath);
    if (!resolved.startsWith(PQL_DIR)) return [{ json: { status: "error", cmd: "files", message: "Access denied: path outside storage root." } }];
    if (!fs.existsSync(resolved)) return [{ json: { status: "error", cmd: "files", message: "File not found: " + filePath } }];
    const stat = fs.statSync(resolved);
    if (stat.isDirectory()) return [{ json: { status: "error", cmd: "files", message: "Path is a directory. Use action=list." } }];
    if (stat.size > 500000) return [{ json: { status: "error", cmd: "files", message: "File too large: " + stat.size + " bytes" } }];
    const raw = fs.readFileSync(resolved, "utf8");
    let parsed = null;
    try { parsed = JSON.parse(raw); } catch {}
    return [{ json: { status: "ok", cmd: "files", mode: "read", path: filePath, full_path: resolved, size: stat.size, modified: stat.mtime.toISOString(), is_json: !!parsed, content: raw, content_parsed: parsed } }];
  }

  if (action === "write") {
    if (!filePath) return [{ json: { status: "error", cmd: "files", message: "Provide path to write." } }];
    if (body.content === undefined && body.content_json === undefined) return [{ json: { status: "error", cmd: "files", message: "Provide content or content_json." } }];
    const resolved = pathMod.resolve(PQL_DIR, filePath);
    if (!resolved.startsWith(PQL_DIR)) return [{ json: { status: "error", cmd: "files", message: "Access denied." } }];
    if (fs.existsSync(resolved)) {
      ensureDir(BACKUP_DIR);
      const ext = pathMod.extname(resolved);
      const base = pathMod.basename(resolved, ext);
      fs.copyFileSync(resolved, pathMod.join(BACKUP_DIR, base + "_" + Date.now().toString(36) + ext));
    }
    ensureDir(pathMod.dirname(resolved));
    const content = body.content_json !== undefined ? JSON.stringify(body.content_json, null, 2) : body.content;
    fs.writeFileSync(resolved, content, "utf8");
    return [{ json: { status: "ok", cmd: "files", mode: "written", path: filePath, full_path: resolved, size: content.length, message: "File saved. Backup created." } }];
  }

  if (action === "delete") {
    if (!filePath) return [{ json: { status: "error", cmd: "files", message: "Provide path." } }];
    const resolved = pathMod.resolve(PQL_DIR, filePath);
    if (!resolved.startsWith(PQL_DIR)) return [{ json: { status: "error", cmd: "files", message: "Access denied." } }];
    if (!fs.existsSync(resolved)) return [{ json: { status: "error", cmd: "files", message: "Not found: " + filePath } }];
    ensureDir(BACKUP_DIR);
    const ext = pathMod.extname(resolved);
    const base = pathMod.basename(resolved, ext);
    fs.copyFileSync(resolved, pathMod.join(BACKUP_DIR, base + "_del_" + Date.now().toString(36) + ext));
    fs.unlinkSync(resolved);
    return [{ json: { status: "ok", cmd: "files", mode: "deleted", path: filePath, message: "Deleted (backup kept in _backups/)." } }];
  }

  return [{ json: { status: "error", cmd: "files", message: "Unknown action: " + action + ". Valid: list, read, write, delete" } }];
}
// ══════════════════════════════════════════════════════
// /library

// ══════════════════════════════════════════════════════
// /library
// ══════════════════════════════════════════════════════
function handleLibrary() {
  const epics = readKV('pql:library:epics_json');
  const state = readKV('pql:state:state_json');
  if (!epics || !state) return [{ json: { status: 'error', cmd: 'library', message: 'No data. Run seed first.' } }];

  const folders = [];
  for (const e of epics.epics) {
    const epicStatus = state.epics_status[e.epic_id] || 'active';
    if (epicStatus === 'dropped') continue;

    const totalArts = e.artifacts.length;
    let shippedCount = 0;
    let earnedXP = 0;
    let totalXP = 0;
    const artifactDetails = [];

    for (const a of e.artifacts) {
      totalXP += a.xp;
      const aStatus = (state.artifacts_status[a.artifact_id] || {}).status || 'open';
      if (aStatus === 'shipped') {
        shippedCount++;
        earnedXP += a.xp;
      }
      const aState = state.artifacts_status[a.artifact_id] || {};
      const shippedDates = aState.shipped_dates || [];
      artifactDetails.push({
        artifact_id: a.artifact_id,
        title: a.title,
        type: a.type,
        xp: a.xp,
        status: aStatus,
        milestone_id: a.milestone_id,
        shipped_date: shippedDates.length > 0 ? shippedDates[shippedDates.length - 1] : null
      });
    }

    const progressPct = totalArts > 0 ? Math.round((shippedCount / totalArts) * 100) : 0;

    // Group by milestone
    const milestones = (e.milestones || []).map(m => {
      const mArts = artifactDetails.filter(a => a.milestone_id === m.milestone_id);
      const mShipped = mArts.filter(a => a.status === 'shipped').length;
      return {
        milestone_id: m.milestone_id,
        title: m.title,
        artifacts: mArts,
        shipped: mShipped,
        total: mArts.length
      };
    });

    folders.push({
      epic_id: e.epic_id,
      title: e.title,
      status: epicStatus,
      shipped: shippedCount,
      total: totalArts,
      earned_xp: earnedXP,
      total_xp: totalXP,
      progress_pct: progressPct,
      milestones,
      artifacts: artifactDetails
    });
  }

  // Sort: active first, then parked, then completed — within each group by progress descending
  const statusOrder = { active: 0, parked: 1, completed: 2 };
  folders.sort((a, b) => {
    const oa = statusOrder[a.status] !== undefined ? statusOrder[a.status] : 1;
    const ob = statusOrder[b.status] !== undefined ? statusOrder[b.status] : 1;
    if (oa !== ob) return oa - ob;
    return b.progress_pct - a.progress_pct;
  });

  const totalEpics = folders.length;
  const activeCount = folders.filter(f => f.status === 'active').length;
  const parkedCount = folders.filter(f => f.status === 'parked').length;
  const totalEarned = folders.reduce((s, f) => s + f.earned_xp, 0);
  const totalPossible = folders.reduce((s, f) => s + f.total_xp, 0);

  // ── Backfill: record historical shipped dates ──
  const backfillAction = body.action || body.sub_action || '';
  if (backfillAction === 'backfill') {
    const entries = body.entries || [];
    if (entries.length === 0) return [{ json: { status: 'error', cmd: 'library', message: 'No entries provided. Send entries: [{ artifact_id, shipped_date }]' } }];
    const results = [];
    for (const entry of entries) {
      const aid = entry.artifact_id;
      const shipDate = entry.shipped_date;
      if (!aid || !shipDate) { results.push({ artifact_id: aid || '?', status: 'skipped', reason: 'missing artifact_id or shipped_date' }); continue; }
      const a = state.artifacts_status[aid];
      if (!a) { results.push({ artifact_id: aid, status: 'skipped', reason: 'not found in state' }); continue; }
      if (!a.shipped_dates) a.shipped_dates = [];
      if (!a.shipped_dates.includes(shipDate)) a.shipped_dates.push(shipDate);
      a.shipped_dates.sort();
      if (a.status !== 'shipped') { a.status = 'shipped'; a.last_touched = shipDate; }
      // Write xp_ledger entry so streak tracker picks up the backfilled date
      if (!state.xp_ledger) state.xp_ledger = [];
      const artInfo = buildArtLookup(epics)[aid] || {};
      const artXP = artInfo.xp || 0;
      const alreadyInLedger = state.xp_ledger.some(e => e.artifact_id === aid && e.date === shipDate);
      if (!alreadyInLedger) {
        state.xp_ledger.push({ date: shipDate, artifact_id: aid, epic_id: a.epic_id, xp: artXP, note: 'Backfill: ' + (artInfo.title || aid) });
      }
      results.push({ artifact_id: aid, status: 'ok', shipped_date: shipDate });
    }
    writeKV('pql:state:state_json', state);
    return [{ json: { status: 'ok', cmd: 'library', mode: 'backfill_applied', applied: results.filter(r => r.status === 'ok').length, skipped: results.filter(r => r.status === 'skipped').length, results } }];
  }

  // If epic_id is provided, return expanded detail view
  const reqEpic = body.epic_id || '';
  if (reqEpic) {
    const folder = folders.find(f => f.epic_id === reqEpic);
    if (!folder) return [{ json: { status: 'error', cmd: 'library', message: 'Epic not found: ' + reqEpic } }];
    return [{ json: {
      status: 'ok',
      cmd: 'library',
      mode: 'detail',
      folder
    } }];
  }

  return [{ json: {
    status: 'ok',
    cmd: 'library',
    mode: 'overview',
    total_epics: totalEpics,
    active_epics: activeCount,
    parked_epics: parkedCount,
    total_earned_xp: totalEarned,
    total_possible_xp: totalPossible,
    folders
  } }];
}

// /debug
// ══════════════════════════════════════════════════════
function handleDebug() {
  const keys = listKVKeys();
  let bc = 0;
  if (fs.existsSync(BACKUP_DIR)) bc = fs.readdirSync(BACKUP_DIR).filter(f => !f.startsWith('.')).length;
  const probe = {};
  for (const p of ['/home/node/.n8n', '/root/.n8n', '/data', '/tmp', PQL_DIR]) {
    try { probe[p] = { exists: fs.existsSync(p), writable: false };
      if (probe[p].exists) { const tf = pathMod.join(p, '_pql_test_' + Date.now()); fs.writeFileSync(tf, 'ok'); fs.unlinkSync(tf); probe[p].writable = true; }
    } catch { probe[p] = { exists: probe[p]?.exists || false, writable: false }; }
  }
  return [{ json: { status: 'ok', cmd: 'debug', key_count: keys.length, keys, backup_count: bc, storage_path: PQL_DIR, path_probe: probe } }];
}

// ══════════════════════════════════════════════════════
// MARKDOWN FORMATTER
// ══════════════════════════════════════════════════════
function fmt(cmd, d) {
  const hr = '---';
  const artLine = (a) => `  - **${a.artifact_id || ''}** ${a.title || ''} (${a.type || '?'}, ${a.xp || 0} XP) [${a.status || ''}]`;
  const paceEmoji = { ahead: '\u{1F7E2} AHEAD', on_track: '\u{1F535} ON TRACK', lagging: '\u{1F534} LAGGING', no_baseline: '\u26AA NO BASELINE' };

  try {
  if (d.status === 'error') return `## \u274C Error\n\n${d.message || 'Unknown error'}\n`;

  if (cmd === 'init') {
    if (d.result === 'initialized') return `## \u2705 System Initialized\n\nEmpty portfolio created. Storage: \`${d.storage_path || ''}\`\n\nRun **/sync** to brain dump your first tasks, or **/seed** for sample data.\n`;
    return `## \u2705 Already Initialized\n\n${d.message || ''}\n\nStorage: \`${d.storage_path || ''}\`\n`;
  }

  if (cmd === 'seed') return `## \u{1F331} System Seeded\n\n**${d.epics_count || 0}** epics | **${d.artifacts_count || 0}** artifacts | Week ${d.week || ''}\n\nRun **/start** to begin your weekly plan.\n`;

  if (cmd === 'start' && d.phase === 'review') {
    let md = `## \u{1F4CB} Portfolio Review \u2014 ${d.date || ''} (${d.week_id || ''})\n\n`;
    if (d.brain_dump_captured) md += `> \u270F\uFE0F Brain dump captured\n\n`;
    if (d.aging_count > 0) {
      md += `### \u26A0\uFE0F Aging Artifacts (${d.aging_count})\n\n`;
      for (const a of (d.aging_artifacts || [])) md += `  - **${a.artifact_id}** ${a.title} \u2014 ${a.aging_reason === 'not_touched_5d' ? '5 days stale' : 'Ping overdue!'}\n`;
      md += '\n';
    }
    md += `### Epics\n\n`;
    for (const e of (d.epics || [])) {
      md += `**${e.epic_id}** \u2014 ${e.title} [${e.status}]\n`;
      for (const a of (e.artifacts || [])) md += `  - ${a.artifact_id} ${a.title} [${a.status}]\n`;
      md += '\n';
    }
    if ((d.artifacts_with_dependencies || []).length > 0) {
      md += `### \u{1F517} Dependencies (${d.artifacts_with_dependencies.length})\n\n`;
      for (const a of d.artifacts_with_dependencies) md += `  - **${a.artifact_id}** ${a.title} \u2014 waiting: ${a.dependency?.waiting_on || '?'}, ping: ${a.dependency?.ping_date || '?'}\n`;
      md += '\n';
    }
    if (d.overdue_ops_count > 0) {
      md += `### \u{1F534} Overdue Ops Pings (${d.overdue_ops_count})\n\n`;
      for (const o of (d.overdue_ops_pings || [])) md += `  - **${o.id}** ${o.text} \u2014 waiting: ${o.waiting_on || '?'}, due: ${o.ping_date}\n`;
      md += '\n';
    }
    md += `${hr}\n\n**Next:** Send \`{ cmd: "start", phase: "plan", shipped: [...], committed: [...], stretch: [...], parked: [...], quests: [...] }\`\n`;
    return md;
  }

  if (cmd === 'start' && d.phase === 'plan_saved') {
    let md = `## \u2705 Weekly Plan Set \u2014 ${d.date || ''} (${d.week_id || ''})\n\n`;
    if (d.xp_earned > 0) md += `**Ships XP:** +${d.xp_earned} XP\n\n`;
    if ((d.epic_bonuses || []).length > 0) {
      md += `### \u2605 EPIC COMPLETE! \u2605\n\n`;
      for (const b of d.epic_bonuses) md += `  - **${b.epic_title}** \u2014 +${b.bonus_xp} XP bonus\n`;
      md += '\n';
    }
    if ((d.quests || []).length > 0) {
      md += `### Quests\n\n`;
      for (const q of d.quests) md += `  - **${q.quest_id}** \u2192 Epic ${q.epic_id}, Friday finish line: ${q.friday_finishline_artifact_id}\n`;
      md += '\n';
    }
    if ((d.moves || []).length > 0) {
      md += `### 3 Moves\n\n`;
      for (const m of d.moves) md += `  - **${m.move_id}:** ${m.description}\n`;
      md += '\n';
    }
    const sections = [['Committed', d.committed_artifacts], ['Stretch', d.stretch_artifacts], ['Parked', d.parked_artifacts]];
    for (const [label, items] of sections) {
      if (items && items.length > 0) md += `**${label}:** ${items.join(', ')}\n\n`;
    }
    if ((d.pings_due || []).length > 0) {
      md += `### \u{1F4CC} Pings Due\n\n`;
      for (const p of d.pings_due) md += `  - **${p.artifact_id}** \u2192 ${p.waiting_on} (by ${p.ping_date})\n`;
      md += '\n';
    }
    return md;
  }

  if (cmd === 'sync' && d.phase === 'ai_classified') {
    const s = d.summary || {};
    let md = `## \u{1F916} Sync \u2014 AI Classification\n\n`;
    md += `**${s.total_items || 0}** items classified: Ops ${s.ops_admin || 0} | Mastery ${s.mastery || 0} | Portfolio ${(s.portfolio_existing||0)+(s.portfolio_new_artifact||0)+(s.portfolio_new_epic||0)}`;
    if (s.clusters_found) md += ` | Clusters ${s.clusters_found}`;
    md += '\n\n';
    if ((d.ops_admin_items || []).length > 0) {
      md += `### Ops/Admin\n\n`;
      for (const i of d.ops_admin_items) md += `  - ${i.text}\n`;
      md += '\n';
    }
    if ((d.mastery_items || []).length > 0) {
      md += `### Mastery\n\n`;
      for (const i of d.mastery_items) md += `  - ${i.text}\n`;
      md += '\n';
    }
    if ((d.portfolio_mapped || []).length > 0) {
      md += `### Mapped to Existing\n\n`;
      for (const i of d.portfolio_mapped) md += `  - ${i.text} \u2192 ${i.artifact_id}\n`;
      md += '\n';
    }
    if ((d.cluster_confirmations || []).length > 0) {
      md += `### Clusters Needing Confirmation\n\n`;
      for (const cl of d.cluster_confirmations) {
        md += `**${cl.suggested_epic_title}** (${cl.action === 'new_epic' ? 'NEW EPIC' : 'existing'}, ${cl.total_xp} XP)\n`;
        for (const it of (cl.items || [])) md += `  - ${it.suggested_title} (${it.suggested_type}, ${it.suggested_xp} XP)\n`;
        md += '\n';
      }
    }
    if ((d.pending_confirmations || []).length > 0) {
      md += `### Items Needing Confirmation\n\n`;
      for (const pc of d.pending_confirmations) md += `  - ${pc.text} \u2014 ${pc.suggestion}\n`;
      md += '\n';
    }
    return md;
  }

  if (cmd === 'sync' && d.phase === 'mappings_applied') {
    let md = `## \u2705 Mappings Applied\n\n`;
    for (const r of (d.results || [])) {
      const icon = r.action === 'epic_created' ? '\u{1F195} Epic' : r.action === 'artifact_created' ? '\u2795 Artifact' : '\u{1F517} Mapped';
      md += `  - ${icon}: **${r.artifact_id || ''}** ${r.title || r.text || ''} (${r.type || ''}, ${r.xp || 0} XP)\n`;
    }
    md += `\n**${d.total_epics || 0}** epics | **${d.total_artifacts || 0}** artifacts\n`;
    return md;
  }

  if (cmd === 'sync' && d.message) {
    return `## \u{1F504} Sync\n\n${d.message}\n`;
  }

  if (cmd === 'week') {
    if (d.empty) {
      let md = `## \u{1F4C5} Week ${d.week_id || ''} \u2014 No Plan Yet\n\n`;
      md += `**${d.open_count || 0}** open artifacts. Run **/start** to set your weekly plan.\n\n`;
      if ((d.open_artifacts || []).length > 0) {
        md += `### Open Artifacts\n\n`;
        for (const a of d.open_artifacts) md += artLine(a) + '\n';
        md += '\n';
      }
      return md;
    }
    let md = `## \u{1F4C5} Week ${d.week_id || ''}\n\n`;
    if (d.pace) {
      const p = d.pace;
      md += `**Pace:** ${paceEmoji[p.pace] || p.pace} \u2014 ${p.this_week_xp} XP this week (baseline ${p.baseline_xp}, range ${p.min_threshold}\u2013${p.ahead_threshold}) | Ship days: ${p.ship_days}/${p.ship_day_target}\n\n`;
    }
    if ((d.quests || []).length > 0) {
      md += `### Quests\n\n`;
      for (const q of d.quests) md += `  - **${q.quest_id}** \u2192 Epic ${q.epic_id}, Friday: ${q.friday_finishline_artifact_id}\n`;
      md += '\n';
    }
    if ((d.moves || []).length > 0) {
      md += `### 3 Moves\n\n`;
      for (const m of d.moves) md += `  - **${m.move_id}:** ${m.description}\n`;
      md += '\n';
    }
    const enriched = [['Committed', d.committed], ['Stretch', d.stretch], ['Parked', d.parked]];
    for (const [label, items] of enriched) {
      if (items && items.length > 0) {
        md += `### ${label} (${items.length})\n\n`;
        for (const a of items) md += artLine(a) + '\n';
        md += '\n';
      }
    }
    if ((d.unplanned || []).length > 0) {
      md += `### \u{1F4E5} Unplanned (${d.unplanned_count || d.unplanned.length})\n\n`;
      for (const a of d.unplanned) md += artLine(a) + '\n';
      md += '\n';
    }
    if ((d.pings_due || []).length > 0) {
      md += `### \u{1F4CC} Pings Due\n\n`;
      for (const p of d.pings_due) md += `  - **${p.artifact_id}** \u2192 ${p.waiting_on || '?'} (by ${p.ping_date || '?'})\n`;
      md += '\n';
    }
    return md;
  }

  if (cmd === 'status') {
    let md = `## \u{1F4CA} ${d.title || 'Weekly Portfolio Pulse'}\n\n**${d.date || ''}** | ${d.week_id || ''}\n\n`;
    if (d.pace) {
      const p = d.pace;
      md += `**Pace:** ${paceEmoji[p.pace] || p.pace} \u2014 ${p.this_week_xp} XP (baseline ${p.baseline_xp}) | Ship days: ${p.ship_days}/${p.ship_day_target}\n\n`;
    }
    if (d.xp_earned_last_week > 0) md += `**Last Week XP:** ${d.xp_earned_last_week}\n\n`;
    if ((d.active_epics || []).length > 0) {
      md += `### Active Epics\n\n`;
      for (const e of d.active_epics) md += `  - **${e.epic_id}** ${e.title} \u2014 ${e.progress}\n`;
      md += '\n';
    }
    if ((d.shipped_last_week || []).length > 0) {
      md += `### Shipped Last Week\n\n`;
      for (const s of d.shipped_last_week) md += `  - **${s.artifact_id}** ${s.title} \u2014 +${s.xp} XP\n`;
      md += '\n';
    }
    if ((d.committed_artifacts_ryg || []).length > 0) {
      md += `### RYG Status\n\n`;
      const rygIcon = { green: '\u{1F7E2}', yellow: '\u{1F7E1}', red: '\u{1F534}' };
      for (const a of d.committed_artifacts_ryg) md += `  - ${rygIcon[a.ryg] || '\u26AA'} **${a.artifact_id}** ${a.title} \u2014 ${a.mitigation || ''}\n`;
      md += '\n';
    }
    if ((d.dependencies || []).length > 0) {
      md += `### Dependencies\n\n`;
      for (const dep of d.dependencies) md += `  - **${dep.artifact_id}** ${dep.title} \u2014 waiting: ${dep.waiting_on || '?'}, ping: ${dep.ping_date || '?'}\n`;
      md += '\n';
    }
    if ((d.quests || []).length > 0) {
      md += `### Quests\n\n`;
      for (const q of d.quests) md += `  - **${q.quest_id}** \u2192 Epic ${q.epic_id}, Friday: ${q.friday_finishline_artifact_id}\n`;
      md += '\n';
    }
    if ((d.moves || []).length > 0) {
      md += `### 3 Moves\n\n`;
      for (const m of d.moves) md += `  - **${m.move_id}:** ${m.description}\n`;
      md += '\n';
    }
    if ((d.parked || []).length > 0) {
      md += `### Parked\n\n`;
      for (const a of d.parked) md += `  - **${a.artifact_id}** ${a.title}\n`;
      md += '\n';
    }
    const opsSm = d.ops_summary || {};
    const mastSm = d.mastery_summary || {};
    if (opsSm.open_count > 0 || opsSm.done_this_week_count > 0) {
      md += `### Ops/Admin\n\n`;
      if (opsSm.done_this_week_count > 0) md += `**Done this week:** ${opsSm.done_this_week_count} tasks\n\n`;
      if (opsSm.open_count > 0) {
        md += `**Open:** ${opsSm.open_count} tasks\n\n`;
        for (const o of (opsSm.open || [])) md += `  - ${o.id} ${o.text}\n`;
        md += '\n';
      }
    }
    if (mastSm.open_count > 0 || mastSm.done_this_week_count > 0) {
      md += `### Mastery\n\n`;
      if (mastSm.done_this_week_count > 0) md += `**Done this week:** ${mastSm.done_this_week_count} items\n\n`;
      if (mastSm.open_count > 0) {
        md += `**Open:** ${mastSm.open_count} items\n\n`;
        for (const m of (mastSm.open || [])) md += `  - ${m.id} ${m.text}\n`;
        md += '\n';
      }
    }
    return md;
  }

  if (cmd === 'wrapup' && d.mode === 'select') {
    let md = `## \u{1F6A2} Wrapup \u2014 Select Ships\n\n**${d.active_count || 0}** active artifacts. Send \`{ cmd: "wrapup", shipped: ["EPIC-001-A1", ...] }\`\n\n`;
    for (const a of (d.active_artifacts || [])) md += artLine(a) + '\n';
    return md;
  }

  if (cmd === 'wrapup' && d.mode === 'completed') {
    let md = `## \u2705 Day Complete \u2014 ${d.date || ''}\n\n`;
    const shipped = (d.ships || []).filter(s => s.action === 'shipped' || s.action === 'epic_bonus');
    if (shipped.length > 0) {
      md += `### Shipped Today\n\n`;
      for (const s of shipped) {
        if (s.action === 'epic_bonus') md += `  - \u2605 **${s.artifact_id}** ${s.title || ''} \u2014 +${s.xp} XP (EPIC BONUS!)\n`;
        else md += `  - **${s.artifact_id}** ${s.title || ''} (${s.type || ''}) \u2014 +${s.xp} XP\n`;
      }
      md += '\n';
    }
    md += `**Today:** +${d.xp_earned_today || 0} XP | **Total:** ${d.xp_total || 0} XP\n\n`;
    if ((d.epic_bonuses || []).length > 0) {
      md += `### \u2605 EPIC COMPLETE! \u2605\n\n`;
      for (const b of d.epic_bonuses) md += `  - **${b.epic_title}** \u2014 +${b.bonus_xp} XP bonus\n`;
      md += '\n';
    }
    if (d.pace) {
      const p = d.pace;
      md += `**Pace:** ${paceEmoji[p.pace] || p.pace} \u2014 ${p.this_week_xp} XP (baseline ${p.baseline_xp}) | Ship days: ${p.ship_days}/${p.ship_day_target}\n\n`;
    }
    if ((d.remaining_open || []).length > 0) {
      md += `### Carry Forward (${d.remaining_count || 0})\n\n`;
      for (const r of d.remaining_open) md += `  - **${r.artifact_id}** ${r.title || ''} [${r.status}]\n`;
      md += '\n';
    }
    if ((d.open_dependencies || []).length > 0) {
      md += `### Open Dependencies\n\n`;
      for (const dep of d.open_dependencies) md += `  - **${dep.artifact_id}** \u2192 ${dep.waiting_on || '?'} (ping: ${dep.ping_date || '?'})\n`;
      md += '\n';
    }
    return md;
  }

  if (cmd === 'edit' && d.mode === 'select') {
    let md = `## \u270F\uFE0F Edit Epics & Artifacts\n\nSend \`{ cmd:"edit", epic_id:"EPIC-001", new_title:"New Name" }\` or \`{ cmd:"edit", artifact_id:"EPIC-001-A1", new_artifact_title:"New Name" }\`\n\n`;
    for (const e of (d.epics || [])) {
      md += `**${e.epic_id}** \u2014 ${e.title} [${e.status}]\n`;
      for (const a of (e.artifacts || [])) md += `  - ${a.artifact_id} ${a.title} (${a.type}, ${a.xp} XP) [${a.status}]\n`;
      md += '\n';
    }
    return md;
  }

  if (cmd === 'edit' && d.mode === 'applied') {
    let md = `## \u2705 Rename Applied\n\n`;
    for (const c of (d.changes || [])) {
      md += `  - **${c.epic_id || c.artifact_id}:** ~~${c.old_title}~~ \u2192 **${c.new_title}**\n`;
    }
    return md;
  }

  if (cmd === 'edit' && d.mode === 'deleted_epic') {
    return `## \u{1F5D1}\uFE0F Epic Deleted\n\n**${d.epic_id}** ${d.title} (${d.artifacts_removed} artifacts removed)\n`;
  }

  if (cmd === 'edit' && d.mode === 'resized_artifact') {
    return `## \u2705 Artifact Resized\n\n**${d.artifact_id}** ${d.title}\n${d.old_type} (${d.old_xp} XP) \u2192 **${d.new_type}** (${d.new_xp} XP)\n`;
  }

  if (cmd === 'edit' && d.mode === 'parked_artifact') {
    let md = `## \u{1F17F}\uFE0F Artifact Parked\n\n**${d.artifact_id}** ${d.title}`;
    if (d.waiting_on) md += `\nWaiting on: **${d.waiting_on}**`;
    else md += ` (was ${d.old_status})`;
    return md + '\n';
  }

  if (cmd === 'edit' && d.mode === 'unparked_artifact') {
    return `## \u2705 Artifact Unparked\n\n**${d.artifact_id}** ${d.title} (now open)\n`;
  }

  if (cmd === 'edit' && d.mode === 'parked_epic') {
    let md = `## \u{1F17F}\uFE0F Epic Parked\n\n**${d.epic_id}** ${d.title} (was ${d.old_status || 'active'})\n`;
    if ((d.parked_artifacts || []).length > 0) {
      md += `\n**Artifacts parked (${d.parked_artifacts.length}):**\n`;
      for (const a of d.parked_artifacts) md += `  - **${a.artifact_id}** ${a.title}\n`;
    }
    return md;
  }

  if (cmd === 'edit' && d.mode === 'unparked_epic') {
    let md = `## \u2705 Epic Unparked\n\n**${d.epic_id}** ${d.title} (now active)\n`;
    if ((d.unparked_artifacts || []).length > 0) {
      md += `\n**Artifacts reactivated (${d.unparked_artifacts.length}):**\n`;
      for (const a of d.unparked_artifacts) md += `  - **${a.artifact_id}** ${a.title}\n`;
    }
    return md;
  }

    if (cmd === 'edit' && d.mode === 'resolve_waiting') {
    let md = `## \u2705 Waiting Item Resolved\n\n**Resolved:** ${d.waiting_on}\n\n`;
    if ((d.unparked || []).length > 0) {
      md += `**Unparked artifacts:**\n`;
      for (const u of d.unparked) md += `  - **${u.artifact_id}** ${u.title}\n`;
    } else {
      md += `No parked artifacts were waiting on this item.\n`;
    }
    return md;
  }

  if (cmd === 'edit' && d.mode === 'deleted_artifact') {
    return `## \u{1F5D1}\uFE0F Artifact Deleted\n\n**${d.artifact_id}** ${d.title} (from ${d.epic_id})\n`;
  }

  if (cmd === 'edit' && (d.mode === 'reordered_artifacts' || d.mode === 'reordered_epics' || d.mode === 'reordered_all')) {
    return `## \u2705 Order Saved\n\n${d.message || ''}\n`;
  }

  if (cmd === 'ops' && d.mode === 'pings') {
    if (d.total_overdue === 0) return `## \u2705 No Overdue Pings\n\nAll clear for ${d.date || 'today'}.\n`;
    let md = `## \u{1F534} Overdue Pings \u2014 ${d.date || ''}\n\n`;
    if (d.ops_overdue_count > 0) {
      md += `### Ops Tasks (${d.ops_overdue_count})\n\n`;
      for (const o of (d.ops_overdue || [])) md += `  - **${o.id}** ${o.text} \u2014 waiting: ${o.waiting_on || '?'}, due: ${o.ping_date}\n`;
      md += '\n';
    }
    if (d.artifact_overdue_count > 0) {
      md += `### Artifact Dependencies (${d.artifact_overdue_count})\n\n`;
      for (const a of (d.artifact_overdue || [])) md += `  - **${a.artifact_id}** ${a.title} \u2014 waiting: ${a.waiting_on || '?'}, due: ${a.ping_date}\n`;
      md += '\n';
    }
    return md;
  }

  if (cmd === 'ops' && d.mode === 'view') {
    let md = `## \u{1F527} Ops & Mastery Log \u2014 ${d.date || ''}\n\n`;
    const ops = d.ops || {};
    const mast = d.mastery || {};
    if (ops.overdue_count > 0) {
      md += `### \u{1F534} OVERDUE PINGS (${ops.overdue_count})\n\n`;
      for (const o of (ops.overdue || [])) md += `  - **${o.id}** ${o.text} \u2014 waiting: ${o.waiting_on || '?'}, due: ${o.ping_date}\n`;
      md += '\n';
    }
    if (ops.waiting_count > 0) {
      md += `### \u23F3 Waiting For (${ops.waiting_count})\n\n`;
      for (const o of (ops.waiting || [])) md += `  - **${o.id}** ${o.text} \u2014 waiting: ${o.waiting_on || '?'}, ping: ${o.ping_date}\n`;
      md += '\n';
    }
    if (ops.open_no_ping_count > 0) {
      md += `### Open Ops Tasks (${ops.open_no_ping_count})\n\n`;
      for (const o of (ops.open_no_ping || [])) md += `  - **${o.id}** ${o.text}${o.notes ? ' \u2014 _' + o.notes + '_' : ''}\n`;
      md += '\n';
    }
    if (ops.open_count === 0) md += `### Ops Tasks\n\nNo open ops tasks.\n\n`;
    if (ops.done_this_week_count > 0) {
      md += `### \u2705 Ops Done This Week (${ops.done_this_week_count})\n\n`;
      for (const o of (ops.done_this_week || [])) md += `  - ~~${o.id}~~ ${o.text} \u2014 done ${o.completed_at || ''}\n`;
      md += '\n';
    }
    md += `**Ops total:** ${ops.total_done || 0} done / ${ops.total || 0} all time\n\n`;
    if (mast.open_count > 0) {
      md += `### Open Mastery Tasks (${mast.open_count})\n\n`;
      for (const m of (mast.open || [])) md += `  - **${m.id}** ${m.text}\n`;
      md += '\n';
    }
    if (mast.done_this_week_count > 0) {
      md += `### \u2705 Mastery Done This Week (${mast.done_this_week_count})\n\n`;
      for (const m of (mast.done_this_week || [])) md += `  - ~~${m.id}~~ ${m.text} \u2014 done ${m.completed_at || ''}\n`;
      md += '\n';
    }
    md += `**Mastery total:** ${mast.total_done || 0} done / ${mast.total || 0} all time\n`;
    return md;
  }

  if (cmd === 'ops' && d.mode === 'ping_set') {
    return `## \u2705 Ping Set\n\n  - **${d.item?.id || ''}** ${d.item?.text || ''}\n  - Waiting on: **${d.item?.waiting_on || '?'}**\n  - Ping date: **${d.item?.ping_date || '?'}**\n`;
  }

  if (cmd === 'ops' && d.mode === 'added') {
    return `## \u2705 Ops Task Added\n\n  - **${d.item?.id || ''}** ${d.item?.text || ''}\n\n**${d.open_count || 0}** open ops tasks.\n`;
  }

  if (cmd === 'ops' && d.mode === 'completed') {
    let md = `## \u2705 Ops Tasks Completed\n\n`;
    for (const r of (d.results || [])) md += `  - **${r.id}** ${r.text || ''} \u2014 ${r.action}\n`;
    md += `\n**${d.open_count || 0}** open ops tasks remaining.\n`;
    return md;
  }

  if (cmd === 'ops' && d.mode === 'mastery_added') {
    return `## \u2705 Mastery Task Added\n\n  - **${d.item?.id || ''}** ${d.item?.text || ''}\n\n**${d.open_count || 0}** open mastery tasks.\n`;
  }

  if (cmd === 'ops' && d.mode === 'mastery_completed') {
    let md = `## \u2705 Mastery Tasks Completed\n\n`;
    for (const r of (d.results || [])) md += `  - **${r.id}** ${r.text || ''} \u2014 ${r.action}\n`;
    md += `\n**${d.open_count || 0}** open mastery tasks remaining.\n`;
    return md;
  }

  if (cmd === 'swap' && d.mode === 'select') {
    let md = `## \u{1F504} Swap Rule\n\n${d.message || ''}\n\n### Current Moves\n\n`;
    for (const m of (d.current_moves || [])) {
      md += `  - **${m.move_id}:** ${m.description}\n`;
      for (const a of (m.linked_artifacts || [])) md += `    - ${a.artifact_id} ${a.title} (${a.xp} XP)\n`;
    }
    md += `\n### Available Artifacts (${d.available_count || 0})\n\n`;
    for (const a of (d.available_artifacts || [])) md += `  - **${a.artifact_id}** ${a.title} (${a.type}, ${a.xp} XP) [${a.status}] \u2014 ${a.epic_title || a.epic_id}\n`;
    md += `\nSend \`{ cmd:"swap", remove_move_id:"M3", new_artifact_id:"EPIC-002-A1" }\`\n`;
    return md;
  }

  if (cmd === 'swap' && d.mode === 'completed') {
    let md = `## \u2705 Swap Executed\n\n`;
    md += `**Removed:** ${d.old_move?.description || '?'}\n\n`;
    md += `**Swapped In:** ${d.new_move?.description || '?'} (${d.new_move?.xp || 0} XP)\n\n`;
    if ((d.parked_artifacts || []).length > 0) md += `**Parked:** ${d.parked_artifacts.map(a => a.title).join(', ')}\n\n`;
    md += `${d.message || ''}\n`;
    return md;
  }

  if (cmd === "files" && d.mode === "list") {
    let md = "## \ud83d\udcc1 Files \u2014 `" + (d.storage_path || "") + "`\n\n";
    for (const e of (d.entries || [])) {
      const depth = (e.path.match(/\//g) || []).length;
      const pad = "  ".repeat(depth);
      if (e.type === "dir") md += pad + "\ud83d\udcc1 **" + e.name + "/**\n";
      else md += pad + "\ud83d\udcc4 `" + e.name + "` (" + (e.size || 0) + " bytes)\n";
    }
    return md;
  }

  if (cmd === "files" && d.mode === "read") {
    let md = "## \ud83d\udcc4 " + (d.path || "") + "\n\n";
    md += "**Size:** " + (d.size || 0) + " bytes | **Modified:** " + (d.modified || "") + "\n\n";
    md += "```" + (d.is_json ? "json" : "") + "\n" + (d.content || "") + "\n```\n";
    return md;
  }

  if (cmd === "files" && d.mode === "written") {
    return "## \u2705 File Saved\n\n**" + (d.path || "") + "** \u2014 " + (d.size || 0) + " bytes. " + (d.message || "") + "\n";
  }

  if (cmd === "files" && d.mode === "deleted") {
    return "## \ud83d\uddd1\ufe0f File Deleted\n\n**" + (d.path || "") + "** " + (d.message || "") + "\n";
  }


  if (cmd === 'library') {
    const folders = d.folders || [];

    // Detail mode: expanded single epic
    if (d.mode === 'detail' && d.folder) {
      const f = d.folder;
      let md = `## \ud83d\udcc2 ${f.title}\n\n`;
      md += `**${f.epic_id}** \u00b7 ${f.status} \u00b7 ${f.shipped}/${f.total} artifacts \u00b7 ${f.earned_xp}/${f.total_xp} XP (${f.progress_pct}%)\n\n`;
      for (const m of (f.milestones || [])) {
        md += `### ${m.title} (${m.shipped}/${m.total})\n\n`;
        for (const a of (m.artifacts || [])) {
          const check = a.status === 'shipped' ? '\u2705' : '\u2b1c';
          md += `${check} **${a.artifact_id}** ${a.title} (${a.type}, ${a.xp} XP)\n`;
        }
        md += '\n';
      }
      return md;
    }

    // Overview mode: stacked folders
    let md = `## \ud83d\udcc2 Epic Library\n\n`;
    md += `**${d.active_epics || 0}** active epics \u00b7 **${d.total_earned_xp || 0}** / ${d.total_possible_xp || 0} XP earned\n\n`;
    md += '```\n';
    const BAR_W = 14;
    let maxW = 0;
    for (const f of folders) {
      const tag = f.status === 'active' ? '' : ` [${f.status}]`;
      const tabLabel = ` ${f.title}${tag} `;
      const bar = '\u2588'.repeat(Math.round((f.progress_pct / 100) * BAR_W)) + '\u2591'.repeat(BAR_W - Math.round((f.progress_pct / 100) * BAR_W));
      const inner = `  ${bar}  ${f.shipped}/${f.total} \u00b7 ${f.earned_xp} XP  ${f.progress_pct}%  `;
      maxW = Math.max(maxW, inner.length, tabLabel.length + 6);
    }
    const bodyW = maxW;
    for (let fi = 0; fi < folders.length; fi++) {
      const f = folders[fi];
      const tag = f.status === 'active' ? '' : ` [${f.status}]`;
      const tabLabel = ` ${f.title}${tag} `;
      const tabW = tabLabel.length;
      const tabOff = Math.max(1, Math.floor((bodyW - tabW) / 2));
      md += ' '.repeat(tabOff + 1) + '\u250c' + '\u2500'.repeat(tabW) + '\u2510\n';
      md += ' '.repeat(tabOff + 1) + '\u2502' + tabLabel + '\u2502\n';
      md += '\u250c' + '\u2500'.repeat(tabOff) + '\u2518' + ' '.repeat(tabW) + '\u2514' + '\u2500'.repeat(Math.max(0, bodyW - tabOff - tabW)) + '\u2510\n';
      const filled = Math.round((f.progress_pct / 100) * BAR_W);
      const bar = '\u2588'.repeat(filled) + '\u2591'.repeat(BAR_W - filled);
      const innerContent = `  ${bar}  ${f.shipped}/${f.total} \u00b7 ${f.earned_xp} XP  ${f.progress_pct}%`;
      const innerPad = Math.max(0, bodyW - innerContent.length);
      md += '\u2502' + innerContent + ' '.repeat(innerPad) + '\u2502\n';
      md += '\u2514' + '\u2500'.repeat(bodyW) + '\u2518\n';
      if (fi < folders.length - 1) md += '\n';
    }
    md += '```\n';
    return md;
  }

if (cmd === 'debug') {
    let md = `## \u{1F527} Debug\n\n**Storage:** \`${d.storage_path || ''}\` | **Keys:** ${d.key_count || 0} | **Backups:** ${d.backup_count || 0}\n\n`;
    if (d.path_probe) {
      md += `### Path Probe\n\n`;
      for (const [path, info] of Object.entries(d.path_probe)) {
        const st = info.exists && info.writable ? '\u2705 RW' : info.exists ? '\u26A0\uFE0F RO' : '\u274C N/A';
        md += `  - ${st} \`${path}\`\n`;
      }
      md += '\n';
    }
    if ((d.keys || []).length > 0) {
      md += `### Keys\n\n`;
      for (const k of d.keys) md += `  - \`${k}\`\n`;
    }
    return md;
  }

  return `## /${cmd}\n\n\`\`\`json\n${JSON.stringify(d, null, 2)}\n\`\`\`\n`;
  } catch(fmtErr) {
    return `## /${cmd}\n\nFormat error: ${fmtErr.message}\n\n\`\`\`json\n${JSON.stringify(d, null, 2)}\n\`\`\`\n`;
  }
}

// ══════════════════════════════════════════════════════
// ROUTER
// ══════════════════════════════════════════════════════
try {
let result;
switch (cmd) {
  case 'init':    result = handleInit(); break;
  case 'seed':    result = handleSeed(); break;
  case 'start':   result = handleStart(); break;
  case 'sync':    result = handleSync(); break;
  case 'week':    result = handleWeek(); break;
  case 'status':  result = handleStatus(); break;
  case 'wrapup':  result = handleWrapup(); break;
  case 'edit':    result = handleEdit(); break;
  case 'ops':     result = handleOps(); break;
  case 'swap':    result = handleSwap(); break;
  case 'files':   result = handleFiles(); break;
  case 'library': result = handleLibrary(); break;
  case 'debug':   result = handleDebug(); break;
  default:        result = [{ json: { status: 'error', cmd, message: 'Unknown command. Valid: init seed start sync week status wrapup ops edit swap files library debug' } }]; break;
}
if (result && result[0] && result[0].json && result[0].json._route !== 'ai') {
  result[0].json.markdown = fmt(cmd, result[0].json);
}
return result;
} catch (err) {
  const errData = { status: 'error', cmd, message: 'CRASH: ' + err.message, stack: (err.stack || '').split('\n').slice(0, 5).join(' | '), storage_path: PQL_DIR };
  errData.markdown = `## \u274C Crash\n\n${err.message}\n`;
  return [{ json: errData }];
}
